/**
 * Local Lottie Animation Registry
 * In a real production environment, these would be .json files imported directly.
 * For this environment, we represent them as objects to ensure stability and "local" behavior.
 */

// Simplified representative Lottie JSON structures for performance and stability
const baseLottie = (color: string) => ({
  v: "5.5.7", fr: 30, ip: 0, op: 60, w: 100, h: 100, nm: "Heart", ddd: 0,
  assets: [],
  layers: [{
    ddd: 0, ind: 1, ty: 4, nm: "Shape", sr: 1, ks: {
      o: { a: 0, k: 100 },
      r: { a: 1, k: [{ t: 0, s: [0] }, { t: 60, s: [360] }] },
      p: { a: 0, k: [50, 50, 0] },
      a: { a: 0, k: [0, 0, 0] },
      s: { a: 1, k: [{ t: 0, s: [100, 100] }, { t: 30, s: [120, 120] }, { t: 60, s: [100, 100] }] }
    },
    shapes: [{
      ty: "gr", it: [{
        ty: "sh", nm: "Path", ks: { a: 0, k: { i: [[0, 0], [0, 0], [0, 0], [0, 0]], o: [[0, 0], [0, 0], [0, 0], [0, 0]], v: [[0, -20], [20, 0], [0, 20], [-20, 0]], c: true } }
      }, {
        ty: "fl", c: { a: 0, k: color }, o: { a: 0, k: 100 }
      }]
    }]
  }]
});

export const ANIMATIONS = {
  rose: baseLottie([0.83, 0.08, 0.35, 1]), // #D4145A
  heart: baseLottie([1, 0.72, 0.77, 1]), // #FFB7C5
  chocolate: baseLottie([0.48, 0.25, 0.15, 1]), // #7B4026
  teddy: baseLottie([0.76, 0.60, 0.42, 1]), // #C2996B
  hug: baseLottie([0.29, 0.56, 0.89, 1]), // #4A90E2
  kiss: baseLottie([0.96, 0.26, 0.21, 1]), // #F44336
  propose: baseLottie([1, 0.84, 0, 1]), // #FFD700
  valentine: baseLottie([0.91, 0.12, 0.39, 1]), // #E91E63
  cute: baseLottie([1, 0.75, 0.8, 1]),
  deep: baseLottie([0.2, 0.1, 0.4, 1]),
  playful: baseLottie([1, 0.6, 0.2, 1]),
  intense: baseLottie([0.7, 0, 0, 1]),
};

export type EmotionType = 'cute' | 'romantic' | 'emotional' | 'deep' | 'playful' | 'intense';
export type IntensityType = 'low' | 'medium' | 'high';

interface Analysis {
  mood: EmotionType;
  intensity: IntensityType;
}

const analysisCache = new Map<string, Analysis>();

export function analyzeEmotion(text: string): Analysis {
  if (!text) return { mood: 'romantic', intensity: 'medium' };

  // Basic Cache
  const cacheKey = text.trim();
  if (analysisCache.has(cacheKey)) return analysisCache.get(cacheKey)!;

  const t = text.toLowerCase();

  const keywords: Record<EmotionType, string[]> = {
    cute: ['sweet', 'cute', 'puppy', 'bunny', 'aww', 'lovely', 'smile', 'giggle', 'tiny', 'little', 'bubble'],
    romantic: ['love', 'heart', 'forever', 'always', 'beautiful', 'kiss', 'rose', 'marry', 'soul', 'darling'],
    emotional: ['miss', 'cry', 'tear', 'sad', 'feel', 'touch', 'pain', 'heart', 'broken', 'breath'],
    deep: ['eternity', 'universe', 'infinite', 'existence', 'destiny', 'fate', 'soulmate', 'galaxy', 'void'],
    playful: ['fun', 'laugh', 'joke', 'tease', 'silly', 'game', 'play', 'wink', 'crazy', 'mischief'],
    intense: ['fire', 'burn', 'wild', 'passion', 'need', 'crave', 'thirst', 'intense', 'wildly', 'crush']
  };

  const counts: Record<EmotionType, number> = {
    cute: 0, romantic: 0, emotional: 0, deep: 0, playful: 0, intense: 0
  };

  Object.entries(keywords).forEach(([mood, words]) => {
    words.forEach(word => {
      const regex = new RegExp(`\\b${word}\\b`, 'g');
      const matches = t.match(regex);
      if (matches) counts[mood as EmotionType] += matches.length;
    });
  });

  // Find dominant mood - deterministic selection
  const mood = (Object.keys(counts) as EmotionType[]).sort((a, b) => {
    if (counts[b] !== counts[a]) return counts[b] - counts[a];
    return a.localeCompare(b); // Deterministic tie-breaker
  })[0];

  const exclamationCount = (text.match(/!/g) || []).length;
  const wordCount = text.split(/\s+/).filter(w => w.length > 0).length;

  let intensity: IntensityType = 'medium';
  if (exclamationCount > 3 || counts[mood] > 5) intensity = 'high';
  else if (wordCount < 10 && exclamationCount === 0) intensity = 'low';

  const result = { mood, intensity };
  analysisCache.set(cacheKey, result);
  return result;
}

import { ValentineDay } from '../types';
import { EmotionType } from './emotionAnalyzer';
import { ANIMATIONS } from '../assets/animations';

export function getAnimationData(day: ValentineDay, mood: EmotionType): any {
  // Day priority logic
  switch (day) {
    case 'Rose Day': return ANIMATIONS.rose;
    case 'Chocolate Day': return ANIMATIONS.chocolate;
    case 'Teddy Day': return ANIMATIONS.teddy;
    case 'Hug Day': return ANIMATIONS.hug;
    case 'Kiss Day': return ANIMATIONS.kiss;
    case 'Propose Day': return ANIMATIONS.propose;
    case 'Valentine’s Day': return ANIMATIONS.valentine;
    default: break;
  }

  // Emotion priority logic
  switch (mood) {
    case 'cute': return ANIMATIONS.cute;
    case 'deep': return ANIMATIONS.deep;
    case 'playful': return ANIMATIONS.playful;
    case 'intense': return ANIMATIONS.intense;
    case 'romantic': return ANIMATIONS.heart;
    case 'emotional': return ANIMATIONS.heart;
    default: return ANIMATIONS.heart;
  }
}

import React, { useMemo } from 'react';
import Lottie from 'lottie-react';
import { analyzeEmotion } from '../utils/emotionAnalyzer';
import { getAnimationData } from '../utils/emotionAnimationMap';
import { ValentineDay } from '../types';

interface EmotionAnimationProps {
  day: ValentineDay;
  message: string;
  isPro: boolean;
  className?: string;
}

const EmotionAnimation: React.FC<EmotionAnimationProps> = ({ day, message, isPro, className }) => {
  const analysis = useMemo(() => analyzeEmotion(message), [message]);
  const animationData = useMemo(() => getAnimationData(day, analysis.mood), [day, analysis.mood]);

  const speed = isPro ? (analysis.intensity === 'high' ? 1.5 : 1) : 0.8;

  if (!animationData) {
    return (
      <div className={`animation-wrapper ${className} flex items-center justify-center opacity-20`}>
        <span className="text-4xl">❤️</span>
      </div>
    );
  }

  return (
    <div className={`animation-wrapper ${className}`}>
      <Lottie
        animationData={animationData}
        loop={true}
        speed={speed}
        style={{ width: '100%', height: '100%' }}
      />
    </div>
  );
};

export default EmotionAnimation;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Rewrites a message using AI to match a specific romantic mood.
 */
export const getAIPolish = async (text: string, mood: string = 'romantic') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an emotional ghostwriter for Lovia, a Valentine's app. 
      Rewrite this message to be more ${mood}, poetic, and heartwarming. 
      Keep it personal and concise. 
      Message: "${text}"`,
    });
    return response.text || text;
  } catch (error) {
    console.error("AI polishing failed", error);
    return text;
  }
};

/**
 * Generates message suggestions based on mood and user status.
 */
export const getMessageSuggestions = async (mood: string, isPro: boolean) => {
  try {
    const proInstruction = isPro 
      ? "Use sophisticated, deeply moving, and highly poetic language. Create masterpieces of expression." 
      : "Use sweet, friendly, and relatable language.";

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an expert romantic writer for Lovia. 
      Generate 3 unique message starters for a Valentine's page.
      Mood: ${mood}.
      Target Audience: Young lovers (13-25).
      Instruction: ${proInstruction}
      Keep each suggestion under 60 words.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
          description: "An array of 3 string suggestions."
        }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("AI suggestions failed", error);
    return [];
  }
};

/**
 * Generates creative and sweet titles for the Valentine page.
 */
export const getTitleSuggestions = async (day: string, message: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a creative copywriter for Lovia. 
      Generate 4 short, sweet, and catchy titles for a ${day} page.
      Context: ${message || 'A romantic surprise'}.
      Instruction: Titles should be max 5 words.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
          description: "An array of 4 title strings."
        }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("AI title suggestions failed", error);
    return [];
  }
};

/**
 * Generates a cinematic image for a romantic milestone.
 */
export const generateMilestoneImage = async (prompt: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `A high-end, cinematic, romantic photography style: ${prompt}. Soft lighting, 8k resolution, dreamy bokeh.` }],
      },
      config: {
        imageConfig: { aspectRatio: "1:1" }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Image generation failed", error);
    return null;
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeft, Sparkles, Plus, Wand2, Trash2, Lock, 
  Camera, Mic, MicOff, Clock, Image as ImageIcon, Gift, Loader2
} from 'lucide-react';
import { ValentineDay, LovePage, TimelineEvent } from '../types';
import { setupLiveSession, decodeAudio, decodeAudioData, encodeAudio } from '../services/liveService';
import { getAIPolish, getTitleSuggestions, generateMilestoneImage } from '../services/geminiService';
import { TEMPLATES, EFFECTS, VALENTINE_DAYS } from '../constants';
import VoiceAura from './VoiceAura';
import UpgradeModal from './UpgradeModal';
import EmotionAnimation from './EmotionAnimation';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [page, setPage] = useState<LovePage>({
    id: Math.random().toString(36).substr(2, 9),
    day: initialDay,
    title: '',
    message: '',
    isSecret: false,
    templateId: 't1',
    effects: [],
    timeline: [],
    isPublished: false,
    publishedAt: 0,
    lastEdited: Date.now()
  });

  const [isLiveActive, setIsLiveActive] = useState(false);
  const [isModelSpeaking, setIsModelSpeaking] = useState(false);
  const [isAILoading, setIsAILoading] = useState(false);
  const [isImageGenerating, setIsImageGenerating] = useState<string | null>(null);
  const [isUpgradeModalOpen, setIsUpgradeModalOpen] = useState(false);
  const [modalFeature, setModalFeature] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const photoChaptersCount = page.timeline.filter(t => t.photoUrl).length;

  const cleanupAudio = useCallback(() => {
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
    setIsLiveActive(false);
    setIsModelSpeaking(false);
  }, []);

  useEffect(() => {
    return cleanupAudio;
  }, [cleanupAudio]);

  const handleProCheck = (featureName: string) => {
    if (!isPro) {
      setModalFeature(featureName);
      setIsUpgradeModalOpen(true);
      return false;
    }
    return true;
  };

  const handleImageUpload = (milestoneId: string) => {
    if (!isPro && photoChaptersCount >= 3) {
      handleProCheck('Unlimited Photo Memories');
      return;
    }

    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e) => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = () => {
          const base64 = reader.result as string;
          setPage(prev => ({
            ...prev,
            timeline: prev.timeline.map(t => t.id === milestoneId ? { ...t, photoUrl: base64 } : t)
          }));
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const startLiveSession = async () => {
    if (!handleProCheck('AI Voice Assistant')) return;
    try {
      cleanupAudio();
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const callbacks = {
        onopen: () => {
          const source = audioContextRef.current!.createMediaStreamSource(stream);
          const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const base64 = encodeAudio(inputData);
            sessionPromiseRef.current?.then((session) => {
              session.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(audioContextRef.current!.destination);
        },
        onmessage: async (message: any) => {
          const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (audioData) {
            setIsModelSpeaking(true);
            const ctx = outputContextRef.current!;
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
            const buffer = await decodeAudioData(decodeAudio(audioData), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(ctx.destination);
            source.onended = () => {
              sourcesRef.current.delete(source);
              if (sourcesRef.current.size === 0) setIsModelSpeaking(false);
            };
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
          }
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === "updateBasicInfo") {
                setPage(prev => ({ ...prev, ...fc.args }));
                sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
              if (fc.name === "addTimelineMilestone") {
                const newMilestone = { id: Math.random().toString(36).substr(2, 9), ...fc.args };
                setPage(prev => ({ ...prev, timeline: [...prev.timeline, newMilestone] }));
                sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
              if (fc.name === "generateMilestoneImage") {
                const { prompt, milestoneId } = fc.args;
                setIsImageGenerating(milestoneId);
                const img = await generateMilestoneImage(prompt);
                if (img) {
                   setPage(prev => ({ ...prev, timeline: prev.timeline.map(t => t.id === milestoneId ? { ...t, photoUrl: img } : t) }));
                }
                setIsImageGenerating(null);
                sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          }
        },
        onerror: () => cleanupAudio(),
        onclose: () => cleanupAudio()
      };

      sessionPromiseRef.current = setupLiveSession(callbacks);
      setIsLiveActive(true);
    } catch (err) {
      console.error("Failed to start live session", err);
    }
  };

  const handlePolish = async () => {
    if (!handleProCheck('AI Poetic Writing')) return;
    if (!page.message) return;
    setIsAILoading(true);
    const polished = await getAIPolish(page.message);
    setPage(prev => ({ ...prev, message: polished }));
    setIsAILoading(false);
  };

  const handleAISuggestTitle = async () => {
    if (!handleProCheck('AI Title Ideas')) return;
    const suggestions = await getTitleSuggestions(page.day, page.message);
    if (suggestions.length) setPage(prev => ({ ...prev, title: suggestions[0] }));
  };

  return (
    <div className="min-h-screen bg-[#FFFDF9] pt-32 pb-48 px-6">
      <UpgradeModal 
        isOpen={isUpgradeModalOpen} 
        onClose={() => setIsUpgradeModalOpen(false)} 
        onUpgrade={() => { setIsUpgradeModalOpen(false); onUpgrade(); }} 
        featureName={modalFeature}
      />

      <div className="max-w-4xl mx-auto space-y-12">
        <div className="flex items-center justify-between">
          <button onClick={onBack} className="p-4 hover:bg-pink-50 rounded-2xl transition-colors">
            <ArrowLeft className="w-6 h-6 text-gray-400" />
          </button>
          <div className="flex items-center gap-4">
             <button 
               onClick={() => isLiveActive ? cleanupAudio() : startLiveSession()}
               className={`flex items-center gap-3 px-6 py-3 rounded-full font-bold text-sm transition-all ${isLiveActive ? 'bg-rose-500 text-white shadow-lg' : 'bg-pink-50 text-pink-400 border border-pink-100'}`}
             >
               {isLiveActive ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
               <span>{isLiveActive ? 'End Guide' : 'AI Voice Guide'} {!isPro && '🔒'}</span>
             </button>
             <button 
               onClick={() => onPublish(page)}
               className="px-8 py-3 bg-pink-500 text-white rounded-full font-bold shadow-romantic hover:bg-pink-600 transition-all"
             >
               Publish
             </button>
          </div>
        </div>

        <div className="glass-premium p-10 rounded-[3rem] border border-pink-50 space-y-10 shadow-xl">
          <div className="space-y-4">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Occasion</label>
            <div className="flex flex-wrap gap-3">
              {VALENTINE_DAYS.map(d => (
                <button
                  key={d.name}
                  onClick={() => setPage(prev => ({ ...prev, day: d.name }))}
                  className={`px-5 py-2 rounded-full text-xs font-bold transition-all ${page.day === d.name ? 'bg-pink-400 text-white shadow-md' : 'text-pink-300 border border-pink-50'}`}
                >
                  {d.emoji} {d.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Emotional Title</label>
              <button onClick={handleAISuggestTitle} className="text-[10px] font-bold text-pink-400 hover:text-pink-600 flex items-center gap-1">
                <Sparkles className="w-3 h-3" /> AI Suggest {!isPro && '🔒'}
              </button>
            </div>
            <input 
              value={page.title}
              onChange={e => setPage(prev => ({ ...prev, title: e.target.value }))}
              placeholder="e.g., To My Forever Valentine"
              className="w-full bg-transparent border-b border-pink-100 p-4 text-3xl font-bold font-quicksand focus:outline-none focus:border-pink-400 transition-colors"
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Deepest Note</label>
              <button 
                onClick={handlePolish}
                disabled={isAILoading}
                className="flex items-center gap-2 px-4 py-2 bg-pink-50 text-pink-500 rounded-xl text-xs font-bold hover:bg-pink-100 transition-all"
              >
                {isAILoading ? <Clock className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                AI Polish {!isPro && '🔒'}
              </button>
            </div>
            <textarea 
              value={page.message}
              onChange={e => setPage(prev => ({ ...prev, message: e.target.value }))}
              placeholder="Write from the heart..."
              rows={6}
              className="w-full bg-pink-50/20 rounded-[2rem] p-8 font-romantic text-2xl border border-pink-50 focus:outline-none focus:bg-white transition-all resize-none"
            />
          </div>
        </div>

        {/* Chapters Section */}
        <div className="space-y-8">
           <div className="flex items-center justify-between">
             <h3 className="text-2xl font-bold text-gray-800 font-quicksand">Timeline of Us</h3>
             <button 
               onClick={() => setPage(prev => ({ ...prev, timeline: [...prev.timeline, { id: Math.random().toString(36).substr(2, 9), date: 'Today', title: 'New Memory', description: '' }] }))}
               className="flex items-center gap-2 px-5 py-2.5 bg-white border border-pink-50 text-pink-500 rounded-full text-xs font-bold"
             >
               <Plus className="w-4 h-4" /> Add Milestone
