import React, { useState, useEffect, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowLeft, Sparkles, Plus, Wand2, Trash2, Lock, 
  Camera, Mic, MicOff, Clock, Image as ImageIcon, Gift, Loader2
} from 'lucide-react';
import { ValentineDay, LovePage, TimelineEvent } from '../types';
import { setupLiveSession, decodeAudio, decodeAudioData, encodeAudio } from '../services/liveService';
import { getAIPolish, getTitleSuggestions, generateMilestoneImage } from '../services/geminiService';
import { TEMPLATES, EFFECTS, VALENTINE_DAYS, PREMIUM_GIFTS } from '../constants';
import VoiceAura from './VoiceAura';
import UpgradeModal from './UpgradeModal';
import EmotionAnimation from './EmotionAnimation';
import PremiumGift, { HiddenLoveGift } from './PremiumGift';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [page, setPage] = useState<LovePage>({
    id: Math.random().toString(36).substr(2, 9),
    day: initialDay,
    title: '',
    message: '',
    isSecret: false,
    templateId: 't1',
    giftId: VALENTINE_DAYS.find(d => d.name === initialDay)?.giftId || 'heart-bloom',
    effects: [],
    timeline: [],
    isPublished: false,
    publishedAt: 0,
    lastEdited: Date.now()
  });

  const [isLiveActive, setIsLiveActive] = useState(false);
  const [isModelSpeaking, setIsModelSpeaking] = useState(false);
  const [isAILoading, setIsAILoading] = useState(false);
  const [isImageGenerating, setIsImageGenerating] = useState<string | null>(null);
  const [isUpgradeModalOpen, setIsUpgradeModalOpen] = useState(false);
  const [modalFeature, setModalFeature] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const photoChaptersCount = page.timeline.filter(t => t.photoUrl).length;

  const cleanupAudio = useCallback(() => {
    if (audioContextRef.current) audioContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
    setIsLiveActive(false);
    setIsModelSpeaking(false);
  }, []);

  useEffect(() => {
    return cleanupAudio;
  }, [cleanupAudio]);

  const handleProCheck = (featureName: string) => {
    if (!isPro) {
      setModalFeature(featureName);
      setIsUpgradeModalOpen(true);
      return false;
    }
    return true;
  };

  const handleDayChange = (dayName: ValentineDay) => {
    const dayData = VALENTINE_DAYS.find(d => d.name === dayName);
    setPage(prev => ({
      ...prev,
      day: dayName,
      giftId: dayData?.giftId || prev.giftId
    }));
  };

  const handleImageUpload = (milestoneId: string) => {
    if (!isPro && photoChaptersCount >= 3) {
      handleProCheck('Unlimited Photo Memories');
      return;
    }

    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = (e) => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (file) {
        const reader = new FileReader();
        reader.onload = () => {
          const base64 = reader.result as string;
          setPage(prev => ({
            ...prev,
            timeline: prev.timeline.map(t => t.id === milestoneId ? { ...t, photoUrl: base64 } : t)
          }));
        };
        reader.readAsDataURL(file);
      }
    };
    input.click();
  };

  const startLiveSession = async () => {
    if (!handleProCheck('AI Voice Assistant')) return;
    try {
      cleanupAudio();
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      outputContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

      const callbacks = {
        onopen: () => {
          const source = audioContextRef.current!.createMediaStreamSource(stream);
          const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            const inputData = e.inputBuffer.getChannelData(0);
            const base64 = encodeAudio(inputData);
            sessionPromiseRef.current?.then((session) => {
              session.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } });
            });
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(audioContextRef.current!.destination);
        },
        onmessage: async (message: any) => {
          const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (audioData) {
            setIsModelSpeaking(true);
            const ctx = outputContextRef.current!;
            nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
            const buffer = await decodeAudioData(decodeAudio(audioData), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(ctx.destination);
            source.onended = () => {
              sourcesRef.current.delete(source);
              if (sourcesRef.current.size === 0) setIsModelSpeaking(false);
            };
            source.start(nextStartTimeRef.current);
            nextStartTimeRef.current += buffer.duration;
            sourcesRef.current.add(source);
          }
          if (message.toolCall) {
            for (const fc of message.toolCall.functionCalls) {
              if (fc.name === "updateBasicInfo") {
                setPage(prev => ({ ...prev, ...fc.args }));
                sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
              if (fc.name === "addTimelineMilestone") {
                const newMilestone = { id: Math.random().toString(36).substr(2, 9), ...fc.args };
                setPage(prev => ({ ...prev, timeline: [...prev.timeline, newMilestone] }));
                sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
              if (fc.name === "generateMilestoneImage") {
                const { prompt, milestoneId } = fc.args;
                setIsImageGenerating(milestoneId);
                const img = await generateMilestoneImage(prompt);
                if (img) {
                   setPage(prev => ({ ...prev, timeline: prev.timeline.map(t => t.id === milestoneId ? { ...t, photoUrl: img } : t) }));
                }
                setIsImageGenerating(null);
                sessionPromiseRef.current?.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: "ok" } } }));
              }
            }
          }
        },
        onerror: () => cleanupAudio(),
        onclose: () => cleanupAudio()
      };

      sessionPromiseRef.current = setupLiveSession(callbacks);
      setIsLiveActive(true);
    } catch (err) {
      console.error("Failed to start live session", err);
    }
  };

  const handlePolish = async () => {
    if (!handleProCheck('AI Poetic Writing')) return;
    if (!page.message) return;
    setIsAILoading(true);
    const polished = await getAIPolish(page.message);
    setPage(prev => ({ ...prev, message: polished }));
    setIsAILoading(false);
  };

  const handleAISuggestTitle = async () => {
    if (!handleProCheck('AI Title Ideas')) return;
    const suggestions = await getTitleSuggestions(page.day, page.message);
    if (suggestions.length) setPage(prev => ({ ...prev, title: suggestions[0] }));
  };

  return (
    <div className="min-h-screen bg-[#FFFDF9] pt-32 pb-48 px-6">
      <UpgradeModal 
        isOpen={isUpgradeModalOpen} 
        onClose={() => setIsUpgradeModalOpen(false)} 
        onUpgrade={() => { setIsUpgradeModalOpen(false); onUpgrade(); }} 
        featureName={modalFeature}
      />

      <div className="max-w-4xl mx-auto space-y-12">
        <div className="flex items-center justify-between">
          <button onClick={onBack} className="p-4 hover:bg-pink-50 rounded-2xl transition-colors">
            <ArrowLeft className="w-6 h-6 text-gray-400" />
          </button>
          <div className="flex items-center gap-4">
             <button 
               onClick={() => isLiveActive ? cleanupAudio() : startLiveSession()}
               className={`flex items-center gap-3 px-6 py-3 rounded-full font-bold text-sm transition-all ${isLiveActive ? 'bg-rose-500 text-white shadow-lg' : 'bg-pink-50 text-pink-400 border border-pink-100'}`}
             >
               {isLiveActive ? <MicOff className="w-4 h-4" /> : <Mic className="w-4 h-4" />}
               <span>{isLiveActive ? 'End Guide' : 'AI Voice Guide'} {!isPro && '🔒'}</span>
             </button>
             <button 
               onClick={() => onPublish(page)}
               className="px-8 py-3 bg-pink-500 text-white rounded-full font-bold shadow-romantic hover:bg-pink-600 transition-all"
             >
               Publish
             </button>
          </div>
        </div>

        <div className="glass-premium p-10 rounded-[3rem] border border-pink-50 space-y-10 shadow-xl">
          <div className="space-y-4">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Occasion</label>
            <div className="flex flex-wrap gap-3">
              {VALENTINE_DAYS.map(d => (
                <button
                  key={d.name}
                  onClick={() => handleDayChange(d.name)}
                  className={`px-5 py-2 rounded-full text-xs font-bold transition-all ${page.day === d.name ? 'bg-pink-400 text-white shadow-md' : 'text-pink-300 border border-pink-50'}`}
                >
                  {d.emoji} {d.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Emotional Title</label>
              <button onClick={handleAISuggestTitle} className="text-[10px] font-bold text-pink-400 hover:text-pink-600 flex items-center gap-1">
                <Sparkles className="w-3 h-3" /> AI Suggest {!isPro && '🔒'}
              </button>
            </div>
            <input 
              value={page.title}
              onChange={e => setPage(prev => ({ ...prev, title: e.target.value }))}
              placeholder="e.g., To My Forever Valentine"
              className="w-full bg-transparent border-b border-pink-100 p-4 text-3xl font-bold font-quicksand focus:outline-none focus:border-pink-400 transition-colors"
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Deepest Note</label>
              <button 
                onClick={handlePolish}
                disabled={isAILoading}
                className="flex items-center gap-2 px-4 py-2 bg-pink-50 text-pink-500 rounded-xl text-xs font-bold hover:bg-pink-100 transition-all"
              >
                {isAILoading ? <Clock className="w-3 h-3 animate-spin" /> : <Wand2 className="w-3 h-3" />}
                AI Polish {!isPro && '🔒'}
              </button>
            </div>
            <textarea 
              value={page.message}
              onChange={e => setPage(prev => ({ ...prev, message: e.target.value }))}
              placeholder="Write from the heart..."
              rows={6}
              className="w-full bg-pink-50/20 rounded-[2rem] p-8 font-romantic text-2xl border border-pink-50 focus:outline-none focus:bg-white transition-all resize-none"
            />
          </div>
        </div>

        {/* Chapters Section */}
        <div className="space-y-8">
           <div className="flex items-center justify-between">
             <h3 className="text-2xl font-bold text-gray-800 font-quicksand">Timeline of Us</h3>
             <button 
               onClick={() => setPage(prev => ({ ...prev, timeline: [...prev.timeline, { id: Math.random().toString(36).substr(2, 9), date: 'Today', title: 'New Memory', description: '' }] }))}
               className="flex items-center gap-2 px-5 py-2.5 bg-white border border-pink-50 text-pink-500 rounded-full text-xs font-bold"
             >
               <Plus className="w-4 h-4" /> Add Milestone
             </button>
           </div>

           <div className="grid gap-6">
             {page.timeline.map((event, idx) => (
               <motion.div key={event.id} layout className="bg-white p-8 rounded-[3rem] border border-pink-50 shadow-sm relative group">
                 <button 
                   onClick={() => setPage(prev => ({ ...prev, timeline: prev.timeline.filter(t => t.id !== event.id) }))}
                   className="absolute top-8 right-8 text-gray-200 hover:text-rose-400 transition-colors"
                 >
                   <Trash2 className="w-4 h-4" />
                 </button>
                 <div className="flex flex-col md:flex-row gap-8">
                   <div 
                     onClick={() => handleImageUpload(event.id)}
                     className="w-full md:w-40 h-40 bg-pink-50 rounded-[2rem] flex flex-col items-center justify-center text-pink-300 cursor-pointer overflow-hidden border-2 border-dashed border-pink-100 hover:border-pink-300 transition-all relative"
                   >
                     {isImageGenerating === event.id ? (
                       <div className="flex flex-col items-center gap-2">
                         <Loader2 className="w-8 h-8 animate-spin" />
                         <span className="text-[8px] font-bold uppercase">Generating...</span>
                       </div>
                     ) : event.photoUrl ? (
                       <img src={event.photoUrl} className="w-full h-full object-cover" />
                     ) : (
                       <>
                         <Camera className="w-8 h-8 mb-2" />
                         <span className="text-[10px] font-bold">Add Photo</span>
                       </>
                     )}
                   </div>
                   <div className="flex-1 space-y-4">
                      <input 
                        value={event.date}
                        onChange={e => {
                          const updated = [...page.timeline];
                          updated[idx].date = e.target.value;
                          setPage(prev => ({ ...prev, timeline: updated }));
                        }}
                        placeholder="Date"
                        className="text-[10px] font-bold uppercase tracking-[0.4em] text-pink-400 focus:outline-none bg-transparent w-full"
                      />
                      <input 
                        value={event.title}
                        onChange={e => {
                          const updated = [...page.timeline];
                          updated[idx].title = e.target.value;
                          setPage(prev => ({ ...prev, timeline: updated }));
                        }}
                        className="w-full text-2xl font-bold text-gray-800 font-quicksand focus:outline-none bg-transparent"
                        placeholder="Memory Title"
                      />
                      <textarea 
                        value={event.description}
                        onChange={e => {
                          const updated = [...page.timeline];
                          updated[idx].description = e.target.value;
                          setPage(prev => ({ ...prev, timeline: updated }));
                        }}
                        className="w-full text-sm text-gray-500 font-medium focus:outline-none resize-none bg-transparent"
                        placeholder="What happened that day?"
                        rows={2}
                      />
                   </div>
                 </div>
               </motion.div>
             ))}
           </div>
        </div>

        {/* Premium Surprise Gift Selection */}
        <div className="space-y-8 pt-10">
          <div className="flex items-center justify-between">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Magical Surprise</label>
            <span className="text-[10px] font-bold text-gray-300 uppercase">Auto-Mapped to your Day</span>
          </div>
          <div className="bg-white p-12 rounded-[4rem] border border-pink-50 flex flex-col items-center gap-10 relative overflow-hidden group shadow-sm hover:shadow-romantic transition-all">
             <div className="absolute inset-0 bg-gradient-to-tr from-pink-50/20 to-transparent pointer-events-none" />
             <div className="relative z-10">
                <HiddenLoveGift giftId={page.giftId || 'eternal-glow'} />
             </div>
             <div className="text-center space-y-4 z-10 max-w-sm">
                <div className="flex items-center justify-center gap-2">
                  <h4 className="font-bold text-gray-800 font-quicksand">Interactive Hidden Reveal</h4>
                  {!isPro && <Lock className="w-3 h-3 text-pink-200" />}
                </div>
                <p className="text-xs text-gray-400 leading-relaxed">
                  Your partner will see a mysterious box. Once they tap it, the custom animation for <span className="text-pink-400 font-bold">{page.day}</span> will play in a cinematic burst.
                </p>
                <div className="flex flex-wrap justify-center gap-2 pt-2">
                  {PREMIUM_GIFTS.map(gift => (
                    <button
                      key={gift.id}
                      onClick={() => gift.isPro ? handleProCheck('Premium Gift Selection') : setPage(prev => ({ ...prev, giftId: gift.id }))}
                      className={`px-4 py-2 rounded-full text-[9px] font-bold uppercase tracking-widest transition-all ${page.giftId === gift.id ? 'bg-pink-400 text-white shadow-md' : 'bg-pink-50 text-pink-300 hover:bg-pink-100'}`}
                    >
                      {gift.name} {gift.isPro && '🔒'}
                    </button>
                  ))}
                </div>
             </div>
          </div>
        </div>

        {/* Templates and Effects */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-6">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Cinematic Template</label>
            <div className="grid grid-cols-2 gap-4">
               {TEMPLATES.map(t => (
                 <button
                   key={t.id}
                   onClick={() => t.isPro ? handleProCheck('Premium Templates') : setPage(prev => ({ ...prev, templateId: t.id }))}
                   className={`p-6 rounded-[2rem] border-2 text-left transition-all ${page.templateId === t.id ? 'border-pink-400 bg-pink-50' : 'border-pink-50 hover:border-pink-100'}`}
                 >
                   <div className="flex items-center justify-between mb-2">
                     <span className="font-bold text-sm text-gray-800">{t.name}</span>
                     {t.isPro && <Lock className="w-3 h-3 text-pink-200" />}
                   </div>
                   <p className="text-[9px] text-gray-400 uppercase font-bold">{t.desc}</p>
                 </button>
               ))}
            </div>
          </div>

          <div className="space-y-6">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Magic Effects</label>
            <div className="flex flex-wrap gap-3">
               {EFFECTS.map(e => (
                 <button
                   key={e.id}
                   onClick={() => {
                    if (e.isPro && !handleProCheck('Cinematic Effects')) return;
                    setPage(prev => ({
                      ...prev,
                      effects: prev.effects.includes(e.id) ? prev.effects.filter(id => id !== e.id) : [...prev.effects, e.id]
                    }));
                   }}
                   className={`px-5 py-3 rounded-full text-[10px] font-bold transition-all border flex items-center gap-2 ${page.effects.includes(e.id) ? 'bg-pink-400 border-pink-400 text-white' : 'border-pink-50 text-pink-300'}`}
                 >
                   {e.icon} {e.name} {e.isPro && '🔒'}
                 </button>
               ))}
            </div>
          </div>
        </div>
      </div>

      <VoiceAura isActive={isLiveActive} isModelSpeaking={isModelSpeaking} />
    </div>
  );
};

export default Builder;

import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Heart, 
  Share2, 
  X, 
  Copy, 
  Check,
  ArrowLeft
} from 'lucide-react';
import { LovePage } from '../types';
import { VALENTINE_DAYS } from '../constants';
import EmotionAnimation from './EmotionAnimation';
import PremiumGift, { HiddenLoveGift } from './PremiumGift';

interface PreviewProps {
  page: LovePage;
  onBack?: () => void;
  isPro: boolean;
}

const Preview: React.FC<PreviewProps> = ({ page, onBack, isPro }) => {
  const [showContent, setShowContent] = useState(false);
  const [revealedLines, setRevealedLines] = useState<string[]>([]);
  const [isFinished, setIsFinished] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);

  const lines = useMemo(() => page.message.split('\n').filter(l => l.trim() !== ''), [page.message]);
  const currentDayInfo = VALENTINE_DAYS.find(d => d.name === page.day);

  useEffect(() => {
    if (showContent) {
      let currentLine = 0;
      const interval = setInterval(() => {
        if (currentLine < lines.length) {
          setRevealedLines(prev => [...prev, lines[currentLine]]);
          currentLine++;
          window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
        } else {
          clearInterval(interval);
          setTimeout(() => { setIsFinished(true); }, 1500);
        }
      }, 3000); 
      return () => clearInterval(interval);
    }
  }, [showContent, lines]);

  const getTemplateStyles = () => {
    switch (page.templateId) {
      case 'p1': return "bg-[#050505] text-rose-100 font-serif"; 
      case 'p2': return "bg-[#000428] text-white font-light tracking-widest"; 
      case 'p3': return "bg-white border-[40px] border-[#fdf2f2] text-rose-900"; 
      case 'p4': return "bg-[#111] text-pink-400 font-mono uppercase"; 
      case 'p5': return "bg-[#fcf8e8] text-[#4a3728] font-serif italic"; 
      default: return "bg-[#FFFDF9] text-gray-800 font-nunito";
    }
  };

  const renderEffect = (id: string) => {
    if (id === 'p1') return (
      <div className="fixed inset-0 pointer-events-none z-10 overflow-hidden">
        {Array.from({ length: 30 }).map((_, i) => (
          <motion.div key={i} className="absolute text-rose-500/20 text-3xl"
            initial={{ y: -100, x: `${Math.random() * 100}%` }}
            animate={{ y: "120vh", rotate: 360 }}
            transition={{ duration: 15 + Math.random() * 10, repeat: Infinity, delay: i * 0.5 }}>❤️</motion.div>
        ))}
      </div>
    );
    if (id === 'p2' || id === 'e2') return (
      <div className="fixed inset-0 pointer-events-none z-10 overflow-hidden">
        {Array.from({ length: 50 }).map((_, i) => (
          <motion.div key={i} className="absolute w-1 h-1 bg-yellow-200 rounded-full"
            animate={{ opacity: [0, 1, 0], scale: [0, 1.5, 0] }}
            transition={{ duration: 3 + Math.random() * 2, repeat: Infinity, delay: Math.random() * 5 }}
            style={{ left: `${Math.random() * 100}%`, top: `${Math.random() * 100}%` }} />
        ))}
      </div>
    );
    return null;
  };

  const shareUrl = `${window.location.origin}${window.location.pathname}#page=${page.id}`;
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=500x500&data=${encodeURIComponent(shareUrl)}&color=ec4899&format=png`;

  return (
    <div className={`min-h-screen relative flex flex-col items-center p-8 md:p-12 text-center overflow-x-hidden ${getTemplateStyles()}`}>
      {page.effects.map(id => <React.Fragment key={id}>{renderEffect(id)}</React.Fragment>)}

      <div className="fixed top-8 right-8 z-[110] flex gap-4">
        {onBack && (
          <button onClick={onBack} className="w-12 h-12 glass-premium rounded-2xl flex items-center justify-center hover:bg-white/30 transition-all border border-white/20">
            <ArrowLeft className="w-6 h-6" />
          </button>
        )}
        <button onClick={() => setShowShareModal(true)} className="px-8 h-12 bg-pink-500 text-white rounded-2xl font-bold shadow-romantic hover:scale-105 transition-all flex items-center gap-2">
          <Share2 className="w-4 h-4" /> <span className="text-[10px] uppercase tracking-widest">Share Love</span>
        </button>
      </div>

      <AnimatePresence mode="wait">
        {!showContent ? (
          <motion.div key="intro" className="my-auto flex flex-col items-center gap-12" exit={{ opacity: 0, scale: 1.1, filter: 'blur(20px)' }}>
            <div className="w-56 h-56 bg-white/10 backdrop-blur-3xl rounded-[4rem] flex items-center justify-center text-pink-500 shadow-romantic border border-white/30">
              <Heart className="w-24 h-24 fill-current animate-pulse" />
            </div>
            <div className="space-y-4">
              <h1 className="text-5xl md:text-8xl font-bold font-quicksand leading-none">A Story Just <br /> For You.</h1>
              <p className="text-xl opacity-60 font-romantic">"Every heartbeat has been building to this."</p>
            </div>
            <button onClick={() => setShowContent(true)} className="px-16 py-6 bg-white text-pink-500 rounded-full font-bold text-2xl shadow-romantic hover:shadow-2xl transition-all border border-pink-100">
              Open the Letter
            </button>
          </motion.div>
        ) : (
          <motion.div key="content" className="max-w-4xl w-full py-48" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
             <header className="mb-48 space-y-8">
               <div className="text-4xl">{currentDayInfo?.emoji}</div>
               <div className="text-xs font-bold uppercase tracking-[1em] opacity-30">{page.day}</div>
               <h2 className="text-6xl md:text-9xl font-bold font-quicksand leading-none">{page.title}</h2>
             </header>

             <article className="space-y-32 px-6">
                {revealedLines.map((line, idx) => (
                  <motion.p key={idx} className="text-4xl md:text-7xl font-romantic leading-snug" initial={{ opacity: 0, y: 30 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 2 }}>
                    {line}
                  </motion.p>
                ))}
             </article>

             {isFinished && (
               <div className="mt-64 space-y-64">
                  <div className="max-w-md mx-auto flex flex-col items-center gap-12">
                    <div className="relative group w-full mb-20">
                      <div className="absolute inset-0 bg-pink-400 blur-[100px] opacity-10" />
                      <div className="relative rounded-[3rem] overflow-hidden shadow-2xl border-[15px] border-white ring-1 ring-pink-50 transform rotate-3 hover:rotate-0 transition-all duration-700 p-8 bg-white">
                          <EmotionAnimation 
                            day={page.day} 
                            message={page.message} 
                            isPro={isPro}
                          />
                      </div>
                    </div>

                    <div className="space-y-8 flex flex-col items-center">
                      <motion.h3 
                        initial={{ opacity: 0 }}
                        whileInView={{ opacity: 1 }}
                        className="text-xs font-bold uppercase tracking-[0.6em] text-pink-300"
                      >
                        A Hidden Surprise
                      </motion.h3>
                      <HiddenLoveGift giftId={page.giftId || 'eternal-glow'} />
                    </div>
                  </div>

                  {page.timeline.length > 0 && (
                    <div className="space-y-48">
                      <h3 className="text-4xl font-bold font-quicksand opacity-40">Our Precious Chapters</h3>
                      {page.timeline.map((event, idx) => (
                        <motion.div key={event.id} initial={{ opacity: 0, y: 50 }} whileInView={{ opacity: 1, y: 0 }} viewport={{ once: true }} className={`flex flex-col items-center gap-12 ${idx % 2 === 0 ? 'md:flex-row text-left' : 'md:flex-row-reverse text-right'}`}>
                           <div className="w-full md:w-1/2">
                              {event.photoUrl && (
                                <img src={event.photoUrl} className="w-full aspect-square object-cover rounded-[3rem] shadow-xl border-8 border-white" />
                              )}
                           </div>
                           <div className="w-full md:w-1/2 space-y-4">
                              <div className="text-xs font-bold text-pink-400 tracking-widest">{event.date}</div>
                              <h4 className="text-5xl font-bold font-quicksand">{event.title}</h4>
                              <p className="text-2xl font-romantic italic opacity-70">"{event.description}"</p>
                           </div>
                        </motion.div>
                      ))}
                    </div>
                  )}

                  <footer className="py-48 flex flex-col items-center gap-12">
                     <Heart className="w-20 h-20 text-pink-500 fill-current" />
                     <p className="text-5xl md:text-8xl font-romantic">Always & Forever.</p>
                     <p className="text-[10px] font-bold uppercase tracking-[0.8em] opacity-30">Created with Lovia</p>
                  </footer>
               </div>
             )}
          </motion.div>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {showShareModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
            <motion.div className="absolute inset-0 bg-gray-900/80 backdrop-blur-3xl" initial={{ opacity: 0 }} animate={{ opacity: 1 }} onClick={() => setShowShareModal(false)} />
            <motion.div className="bg-white rounded-[4rem] p-12 max-w-lg w-full text-center relative shadow-2xl" initial={{ scale: 0.9, y: 40 }} animate={{ scale: 1, y: 0 }}>
              <button onClick={() => setShowShareModal(false)} className="absolute top-8 right-8 text-gray-300 hover:text-pink-500 transition-colors">
                <X className="w-8 h-8" />
              </button>
              <div className="space-y-8 flex flex-col items-center">
                 <div className="text-left w-full">
                    <h3 className="text-4xl font-bold text-gray-800 font-quicksand">The Love Passport</h3>
                    <p className="text-xs text-pink-400 font-bold uppercase tracking-widest mt-1">Unique Link for your Partner</p>
                 </div>
                 <div className="bg-white p-6 rounded-[2.5rem] border-2 border-pink-50 shadow-inner">
                    <img src={qrUrl} className="w-64 h-64" />
                 </div>
                 <div className="w-full space-y-4">
                    <button onClick={() => { navigator.clipboard.writeText(shareUrl); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="w-full py-5 bg-gray-50 rounded-[2rem] font-bold text-lg flex items-center justify-center gap-3 border border-gray-100">
                      {copied ? <Check className="w-6 h-6 text-green-500" /> : <Copy className="w-6 h-6" />}
                      {copied ? 'Captured!' : 'Copy Private Link'}
                    </button>
                    {!isPro && <p className="text-[10px] text-gray-400 uppercase font-bold tracking-widest">Upgrade to PRO to Download Passport HQ</p>}
                 </div>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default Preview;

