.photo-slot {
  position: relative;
  width: 120px;
  height: 120px;
  border-radius: 16px;
  overflow: hidden;
  border: 3px solid white;
  background: #fff;
  box-shadow: 0 10px 25px -5px rgba(255, 183, 197, 0.4);
  transition: all 0.5s cubic-bezier(0.16, 1, 0.3, 1);
}

.photo-slot:hover {
  transform: scale(1.05);
  box-shadow: 0 15px 35px -5px rgba(255, 183, 197, 0.6);
}

.photo-slot img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.line-reveal {
  opacity: 0;
  transform: translateY(20px);
  animation: reveal 1s forwards;
}

@keyframes reveal {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.glass-polish {
  backdrop-filter: blur(20px) saturate(180%);
  -webkit-backdrop-filter: blur(20px) saturate(180%);
  background-color: rgba(255, 255, 255, 0.7);
  border: 1px solid rgba(255, 255, 255, 0.3);
}

body {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

.parallax-3px {
  transform: translateY(var(--parallax-y, 0));
}

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Heart, Camera, Image as ImageIcon } from 'lucide-react';

interface PremiumGiftProps {
  giftId: string;
  className?: string;
  photoUrl?: string;
  isPro?: boolean;
}

export const HiddenLoveGift: React.FC<PremiumGiftProps> = ({ giftId, className = "", photoUrl: initialPhotoUrl, isPro = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [localPhoto, setLocalPhoto] = useState<string | null>(initialPhotoUrl || null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (initialPhotoUrl) setLocalPhoto(initialPhotoUrl);
  }, [initialPhotoUrl]);

  const handleBoxClick = (e: React.MouseEvent) => {
    if (!isOpen) {
      setIsOpen(true);
    } else {
      // Logic for photo upload if the box is already open (unlimited for pro)
      if (isPro || !localPhoto) {
        fileInputRef.current?.click();
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = reader.result as string;
        setLocalPhoto(base64);
        // Persist to local storage hack to bridge Builder state if possible
        const hash = window.location.hash;
        if (hash.startsWith('#page=')) {
          const id = hash.replace('#page=', '');
          const projects = JSON.parse(localStorage.getItem('lovia_projects') || '[]');
          const idx = projects.findIndex((p: any) => p.id === id);
          if (idx !== -1) {
            projects[idx].giftPhotoUrl = base64;
            localStorage.setItem('lovia_projects', JSON.stringify(projects));
          }
        }
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className={`flex flex-col items-center gap-8 ${className}`}>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept="image/*" 
        className="hidden" 
      />
      <AnimatePresence mode="wait">
        {!isOpen ? (
          <motion.div
            key="closed-box"
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ 
              scale: [1, 1.04, 1], 
              opacity: 1,
              y: [0, -10, 0]
            }}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.95 }}
            transition={{ 
              duration: 3, 
              repeat: Infinity,
              scale: { duration: 2, repeat: Infinity }
            }}
            onClick={handleBoxClick}
            className="cursor-pointer group relative"
          >
            <div className="absolute inset-0 bg-pink-200 blur-3xl opacity-20 group-hover:opacity-40 transition-opacity" />
            <div className="relative w-48 h-48 bg-gradient-to-br from-pink-50 to-lavender-50 rounded-[3rem] border-4 border-pink-100 shadow-romantic flex flex-col items-center justify-center gap-3 overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
                <Sparkles className="w-full h-full text-pink-300" />
              </div>
              <motion.div
                animate={{ scale: [1, 1.2, 1] }}
                transition={{ duration: 1.5, repeat: Infinity }}
              >
                <Heart className="w-12 h-12 text-pink-400 fill-pink-400" />
              </motion.div>
              <span className="text-[10px] font-bold uppercase tracking-widest text-pink-400 text-center px-4 leading-relaxed">
                Tap to open your<br/>surprise 💝
              </span>
            </div>
          </motion.div>
        ) : (
          <motion.div
            key="opened-gift"
            initial={{ scale: 0.5, opacity: 0, filter: 'blur(20px)' }}
            animate={{ scale: 1, opacity: 1, filter: 'blur(0px)' }}
            transition={{ type: "spring", damping: 12, stiffness: 100, delay: 0.4 }}
            className="flex flex-col items-center gap-8"
          >
            <div className="relative flex flex-col items-center gap-8">
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="absolute inset-0 bg-pink-400 blur-[100px] opacity-10 pointer-events-none"
              />

              {/* Main Gift Animation */}
              <PremiumGift giftId={giftId} className="w-64 h-64" />

              {/* Square 1:1 Photo Slot */}
              <motion.div 
                initial={{ opacity: 0, y: 20, scale: 0.8 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ delay: 0.8, duration: 0.8 }}
                onClick={handleBoxClick}
                className="photo-slot cursor-pointer group"
              >
                {localPhoto ? (
                  <motion.img 
                    initial={{ scale: 1.2, filter: 'blur(10px)' }}
                    animate={{ scale: 1, filter: 'blur(0px)' }}
                    src={localPhoto} 
                    alt="Love Memory" 
                  />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center bg-pink-50 text-pink-300 gap-1">
                    <Camera className="w-6 h-6" />
                    <span className="text-[8px] font-bold uppercase tracking-widest">Add Photo</span>
                  </div>
                )}
                {isPro && localPhoto && (
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <ImageIcon className="w-6 h-6 text-white" />
                  </div>
                )}
              </motion.div>
            </div>

            <motion.p
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 1.2 }}
              className="text-pink-400 font-romantic text-2xl"
            >
              {localPhoto ? "A precious moment for us..." : "Add a photo to make it special"}
            </motion.p>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

