import React, { useState, useEffect, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Heart, 
  Share2, 
  X, 
  Copy, 
  Check,
  ArrowLeft
} from 'lucide-react';
import { LovePage } from '../types';
import { VALENTINE_DAYS } from '../constants';
import EmotionAnimation from './EmotionAnimation';
import { HiddenLoveGift } from './PremiumGift';

interface PreviewProps {
  page: LovePage;
  onBack?: () => void;
  isPro: boolean;
}

const Preview: React.FC<PreviewProps> = ({ page, onBack, isPro }) => {
  const [showContent, setShowContent] = useState(false);
  const [revealedLinesCount, setRevealedLinesCount] = useState(0);
  const [isFinished, setIsFinished] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);
  const [scrollProgress, setScrollProgress] = useState(0);

  const lines = useMemo(() => page.message.split('\n').filter(l => l.trim() !== ''), [page.message]);
  const currentDayInfo = VALENTINE_DAYS.find(d => d.name === page.day);

  useEffect(() => {
    const handleScroll = () => {
      const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
      const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      const scrolled = winScroll / height;
      setScrollProgress(scrolled);
      // Set parallax variable
      document.documentElement.style.setProperty('--parallax-y', `${winScroll * 0.05}px`);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    if (showContent) {
      let count = 0;
      const timer = setInterval(() => {
        if (count < lines.length) {
          setRevealedLinesCount(prev => prev + 1);
          count++;
          // Auto scroll slightly as text appears
          window.scrollBy({ top: 100, behavior: 'smooth' });
        } else {
          clearInterval(timer);
          setTimeout(() => { setIsFinished(true); }, 1000);
        }
      }, 2000); // 2 second delay per line for a romantic reading pace
      return () => clearInterval(timer);
    }
  }, [showContent, lines]);

  const getTemplateStyles = () => {
    switch (page.templateId) {
      case 'p1': return "bg-[#050505] text-rose-100 font-serif"; 
      case 'p2': return "bg-[#000428] text-white font-light tracking-widest"; 
      case 'p3': return "bg-white border-[40px] border-[#fdf2f2] text-rose-900"; 
      case 'p4': return "bg-[#111] text-pink-400 font-mono uppercase"; 
      case 'p5': return "bg-[#fcf8e8] text-[#4a3728] font-serif italic"; 
      default: return "bg-[#FFFDF9] text-gray-800 font-nunito";
    }
  };

  const renderSubtleHearts = () => (
    <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden opacity-[0.05]">
      {Array.from({ length: 15 }).map((_, i) => (
        <motion.div
          key={i}
          className="absolute text-pink-400"
          initial={{ y: '110vh', x: `${Math.random() * 100}vw` }}
          animate={{ y: '-10vh' }}
          transition={{ duration: 30 + Math.random() * 20, repeat: Infinity, delay: i * 2 }}
        >
          <Heart fill="currentColor" size={20 + Math.random() * 40} />
        </motion.div>
      ))}
    </div>
  );

  const renderEffect = (id: string) => {
    if (id === 'p1') return (
      <div className="fixed inset-0 pointer-events-none z-10 overflow-hidden">
        {Array.from({ length: 30 }).map((_, i) => (
          <motion.div key={i} className="absolute text-rose-500/20 text-3xl"
            initial={{ y: -100, x: `${Math.random() * 100}%` }}
            animate={{ y: "120vh", rotate: 360 }}
            transition={{ duration: 15 + Math.random() * 10, repeat: Infinity, delay: i * 0.5 }}>❤️</motion.div>
        ))}
      </div>
    );
    if (id === 'p2' || id === 'e2') return (
      <div className="fixed inset-0 pointer-events-none z-10 overflow-hidden">
        {Array.from({ length: 50 }).map((_, i) => (
          <motion.div key={i} className="absolute w-1 h-1 bg-yellow-200 rounded-full"
            animate={{ opacity: [0, 1, 0], scale: [0, 1.5, 0] }}
            transition={{ duration: 3 + Math.random() * 2, repeat: Infinity, delay: Math.random() * 5 }}
            style={{ left: `${Math.random() * 100}%`, top: `${Math.random() * 100}%` }} />
        ))}
      </div>
    );
    return null;
  };

  const shareUrl = `${window.location.origin}${window.location.pathname}#page=${page.id}`;
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=500x500&data=${encodeURIComponent(shareUrl)}&color=ec4899&format=png`;

  return (
    <motion.div 
      initial={{ opacity: 0, scale: 0.98 }}
      animate={{ opacity: 1, scale: 1 }}
      transition={{ duration: 0.8, ease: "easeOut" }}
      className={`min-h-screen relative flex flex-col items-center p-8 md:p-12 text-center overflow-x-hidden ${getTemplateStyles()}`}
    >
      {renderSubtleHearts()}
      {page.effects.map(id => <React.Fragment key={id}>{renderEffect(id)}</React.Fragment>)}

      <div className="fixed top-8 right-8 z-[110] flex gap-4">
        {onBack && (
          <motion.button 
            whileHover={{ scale: 1.05 }} 
            whileTap={{ scale: 0.95 }}
            onClick={onBack} 
            className="w-12 h-12 glass-premium rounded-2xl flex items-center justify-center hover:bg-white/30 transition-all border border-white/20 shadow-sm"
          >
            <ArrowLeft className="w-6 h-6" />
          </motion.button>
        )}
        <motion.button 
          whileHover={{ scale: 1.05 }} 
          whileTap={{ scale: 0.95 }}
          onClick={() => setShowShareModal(true)} 
          className="px-8 h-12 bg-pink-500 text-white rounded-2xl font-bold shadow-romantic hover:bg-pink-600 transition-all flex items-center gap-2"
        >
          <Share2 className="w-4 h-4" /> <span className="text-[10px] uppercase tracking-widest">Share Love</span>
        </motion.button>
      </div>

      <AnimatePresence mode="wait">
        {!showContent ? (
          <motion.div key="intro" className="my-auto flex flex-col items-center gap-12" exit={{ opacity: 0, scale: 1.1, filter: 'blur(20px)' }}>
            <motion.div 
              animate={{ y: [0, -10, 0] }}
              transition={{ duration: 4, repeat: Infinity }}
              className="w-56 h-56 bg-white/10 backdrop-blur-3xl rounded-[4rem] flex items-center justify-center text-pink-500 shadow-romantic border border-white/30"
            >
              <Heart className="w-24 h-24 fill-current animate-pulse" />
            </motion.div>
            <div className="space-y-4">
              <h1 className="text-5xl md:text-8xl font-bold font-quicksand leading-none tracking-tight">A Story Just <br /> For You.</h1>
              <p className="text-xl opacity-60 font-romantic italic">"Every heartbeat has been building to this moment."</p>
            </div>
            <motion.button 
              whileHover={{ scale: 1.05, boxShadow: "0 20px 40px -10px rgba(255,183,197,0.5)" }}
              whileTap={{ scale: 0.95 }}
              onClick={() => setShowContent(true)} 
              className="px-16 py-6 bg-white text-pink-500 rounded-full font-bold text-2xl shadow-romantic hover:shadow-2xl transition-all border border-pink-100"
            >
              Open the Letter
            </motion.button>
          </motion.div>
        ) : (
          <motion.div key="content" className="max-w-4xl w-full py-48" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
             <header className="mb-48 space-y-8 parallax-3px">
               <motion.div 
                 initial={{ scale: 0 }} 
                 animate={{ scale: 1 }} 
                 className="text-5xl"
               >
                {currentDayInfo?.emoji}
               </motion.div>
               <div className="text-xs font-bold uppercase tracking-[1em] opacity-30">{page.day}</div>
               <h2 className="text-6xl md:text-9xl font-bold font-quicksand leading-none tracking-tighter">{page.title}</h2>
             </header>

