import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Heart, Camera, Image as ImageIcon } from 'lucide-react';

interface PremiumGiftProps {
  giftId: string;
  className?: string;
  photoUrl?: string;
  isPro?: boolean;
}

export const HiddenLoveGift: React.FC<PremiumGiftProps> = ({ giftId, className = "", photoUrl: initialPhotoUrl, isPro = false }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [localPhoto, setLocalPhoto] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Load from specific page ID if present in hash, otherwise fallback to generic
    const hash = window.location.hash;
    const pageId = hash.startsWith('#page=') ? hash.replace('#page=', '') : 'default';
    const saved = localStorage.getItem(`lovia_gift_photo_${pageId}`);

    if (saved) {
      setLocalPhoto(saved);
    } else if (initialPhotoUrl) {
      setLocalPhoto(initialPhotoUrl);
    }
  }, [initialPhotoUrl]);

  const handleBoxClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isOpen) {
      setIsOpen(true);
    } else {
      if (isPro || !localPhoto) {
        fileInputRef.current?.click();
      }
    }
  };

  const processImage = (file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const size = Math.min(img.width, img.height, 800);
        canvas.width = size;
        canvas.height = size;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const sourceSize = Math.min(img.width, img.height);
          const xOffset = (img.width - sourceSize) / 2;
          const yOffset = (img.height - sourceSize) / 2;
          ctx.drawImage(img, xOffset, yOffset, sourceSize, sourceSize, 0, 0, size, size);
          const base64 = canvas.toDataURL('image/jpeg', 0.8);
          setLocalPhoto(base64);

          const hash = window.location.hash;
          const pageId = hash.startsWith('#page=') ? hash.replace('#page=', '') : 'default';
          localStorage.setItem(`lovia_gift_photo_${pageId}`, base64);
        }
      };
      img.src = event.target?.result as string;
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className={`flex flex-col items-center gap-8 ${className}`}>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && processImage(e.target.files[0])} 
        accept="image/*" 
        className="hidden" 
      />
      <AnimatePresence mode="wait">
        {!isOpen ? (
          <motion.div
            key="closed-box"
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ 
              scale: [1, 1.04, 1], 
              opacity: 1,
              y: [0, -10, 0]
            }}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.95 }}
            transition={{ duration: 3, repeat: Infinity }}
            onClick={handleBoxClick}
            className="cursor-pointer group relative"
          >
            <div className="absolute inset-0 bg-pink-200 blur-3xl opacity-20 group-hover:opacity-40 transition-opacity" />
            <div className="relative w-48 h-48 bg-gradient-to-br from-pink-50 to-lavender-50 rounded-[3rem] border-4 border-pink-100 shadow-romantic flex flex-col items-center justify-center gap-3 overflow-hidden">
              <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
                <Sparkles className="w-full h-full text-pink-300" />
              </div>
              <motion.div animate={{ scale: [1, 1.2, 1] }} transition={{ duration: 1.5, repeat: Infinity }}>
                <Heart className="w-12 h-12 text-pink-400 fill-pink-400" />
              </motion.div>
              <span className="text-[10px] font-bold uppercase tracking-widest text-pink-400 text-center px-4 leading-relaxed">
                Tap to open your<br/>surprise 💝
              </span>
            </div>
          </motion.div>
        ) : (
          <motion.div
            key="opened-gift"
            initial={{ scale: 0.5, opacity: 0, filter: 'blur(20px)' }}
            animate={{ scale: 1, opacity: 1, filter: 'blur(0px)' }}
            transition={{ type: "spring", damping: 12, stiffness: 100, delay: 0.2 }}
            className="flex flex-col items-center gap-8"
          >
            <div className="relative flex flex-col items-center gap-8">
              <motion.div 
                animate={{ opacity: [0.1, 0.2, 0.1], scale: [1, 1.2, 1] }}
                transition={{ duration: 4, repeat: Infinity }}
                className="absolute inset-0 bg-pink-400 blur-[100px] opacity-10 pointer-events-none"
              />

              <PremiumGift giftId={giftId} className="w-64 h-64" />

              <motion.div 
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.5 }}
                onClick={handleBoxClick}
                className="relative w-40 h-40 rounded-2xl overflow-hidden border-4 border-white bg-white shadow-[0_10px_30px_-10px_rgba(255,183,197,0.5)] cursor-pointer group transition-transform hover:scale-105"
              >
                {localPhoto ? (
                  <img src={localPhoto} className="w-full h-full object-cover" alt="Love Memory" />
                ) : (
                  <div className="w-full h-full flex flex-col items-center justify-center bg-pink-50 text-pink-300 gap-2">
                    <Camera className="w-8 h-8" />
                    <span className="text-[10px] font-bold uppercase tracking-widest">Add Photo</span>
                  </div>
                )}
                {isPro && localPhoto && (
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <ImageIcon className="w-6 h-6 text-white" />
                  </div>
                )}
              </motion.div>
            </div>

            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.8 }}
              className="text-pink-400 font-romantic text-2xl"
            >
              {localPhoto ? "A moment forever..." : "Tap the slot to add a memory"}
            </motion.p>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

const PremiumGift: React.FC<PremiumGiftProps> = ({ giftId, className = "" }) => {
  try {
    switch (giftId) {
      case 'rose-petals': 
        return (
          <div className={`relative w-full h-full flex items-center justify-center overflow-hidden ${className}`}>
            {[...Array(15)].map((_, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, y: -20 }}
                animate={{ opacity: [0, 1, 0], y: [0, 200], x: [0, Math.sin(i) * 50], rotate: 360 }}
                transition={{ duration: 4 + Math.random() * 2, repeat: Infinity, delay: i * 0.3 }}
                className="absolute text-rose-300"
                style={{ left: `${Math.random() * 100}%` }}
              >
                <Heart size={16} fill="currentColor" />
              </motion.div>
            ))}
            <motion.div animate={{ scale: [0.9, 1.1, 0.9] }} transition={{ duration: 3, repeat: Infinity }}>
              <Heart className="w-24 h-24 text-rose-500 fill-current" />
            </motion.div>
          </div>
        );
      case 'heart-bloom': 
        return (
          <div className={`relative w-full h-full flex items-center justify-center ${className}`}>
            <motion.div
              animate={{ scale: [1, 1.2, 1], filter: ["blur(0px)", "blur(2px)", "blur(0px)"] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="text-yellow-500 drop-shadow-[0_0_15px_rgba(255,215,0,0.6)]"
            >
              <Sparkles size={80} />
            </motion.div>
          </div>
        );
      case 'soft-glow':
        return (
          <div className={`relative w-full h-full flex items-center justify-center overflow-hidden ${className}`}>
            <motion.div
              animate={{ opacity: [0.2, 0.5, 0.2], scale: [1, 1.5, 1] }}
              transition={{ duration: 4, repeat: Infinity }}
              className="w-40 h-40 bg-amber-200/40 rounded-full blur-3xl"
            />
            <span className="text-6xl z-10">🍫</span>
          </div>
        );
      case 'hug-aura': 
        return (
          <div className={`relative w-full h-full flex items-center justify-center ${className}`}>
            <motion.div
              animate={{ scale: [1, 1.1, 1] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="relative z-10 text-7xl"
            >
              🧸
            </motion.div>
            <motion.div
              animate={{ scale: [1, 1.6], opacity: [0.5, 0] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="absolute w-40 h-40 bg-pink-200 rounded-full"
            />
          </div>
        );
      case 'promise-seal':
        return (
          <div className={`relative w-full h-full flex items-center justify-center ${className}`}>
            <motion.div animate={{ rotate: 360 }} transition={{ duration: 20, repeat: Infinity, ease: "linear" }}>
              <svg width="100" height="100" viewBox="0 0 24 24" fill="none" stroke="#A78BFA" strokeWidth="1">
                <circle cx="12" cy="12" r="10" strokeDasharray="4 4" />
              </svg>
            </motion.div>
            <span className="absolute text-5xl">🤝</span>
          </div>
        );
      case 'warm-pulse': 
        return (
          <div className={`relative w-full h-full flex items-center justify-center ${className}`}>
             <motion.div
              animate={{ scale: [1, 1.3, 1], backgroundColor: ['#FEE2E2', '#FECACA', '#FEE2E2'] }}
              transition={{ duration: 2, repeat: Infinity }}
              className="w-40 h-40 rounded-full flex items-center justify-center shadow-lg"
            >
              <span className="text-5xl">🫂</span>
            </motion.div>
          </div>
        );
      case 'kiss-trail':
        return (
          <div className={`relative w-full h-full flex items-center justify-center ${className}`}>
            {[...Array(6)].map((_, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, x: -50 }}
                animate={{ opacity: [0, 1, 0], x: [0, 100], y: [0, Math.sin(i) * 30] }}
                transition={{ duration: 3, repeat: Infinity, delay: i * 0.5 }}
                className="absolute text-rose-400 text-3xl"
              >
                💋
              </motion.div>
            ))}
          </div>
        );
      case 'eternal-glow': 
        return (
          <div className={`relative w-full h-full flex items-center justify-center ${className}`}>
            <motion.div
              animate={{ rotate: 360, scale: [1, 1.1, 1] }}
              transition={{ rotate: { duration: 10, repeat: Infinity, ease: "linear" }, scale: { duration: 3, repeat: Infinity } }}
              className="absolute w-60 h-60 bg-gradient-to-tr from-yellow-200 via-pink-300 to-rose-400 rounded-full blur-3xl opacity-30"
            />
            <Heart size={80} className="text-rose-500 fill-current drop-shadow-xl" />
          </div>
        );
      default:
        return <div className="text-pink-100 text-6xl">❤️</div>;
    }
  } catch (err) {
    return <div className="text-pink-100 text-6xl">❤️</div>;
  }
};

export default PremiumGift;

