  ArrowLeft, Sparkles, Plus, Wand2, Trash2, Mic, MicOff, Clock, Camera, Loader2
} from 'lucide-react';
import { ValentineDay, LovePage } from '../types';
import { getAIPolish, getTitleSuggestions, generateMilestoneImage } from '../services/geminiService';
import { VALENTINE_DAYS, PREMIUM_GIFTS, TEMPLATES, EFFECTS } from '../constants';
