interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [page, setPage] = useState<LovePage>(() => {
    const saved = localStorage.getItem('lovia_draft');
    return saved ? JSON.parse(saved) : {
      id: Math.random().toString(36).substr(2, 9),
      day: initialDay,
      title: '',
      message: '',
      isSecret: false,
      templateId: 't1',
      giftId: VALENTINE_DAYS.find(d => d.name === initialDay)?.giftId || 'eternal-glow',
      effects: [],
      timeline: [],
      isPublished: false,
      publishedAt: 0,
      lastEdited: Date.now()
    };
  });

  const [isAILoading, setIsAILoading] = useState(false);
  const [isUpgradeModalOpen, setIsUpgradeModalOpen] = useState(false);
  const [modalFeature, setModalFeature] = useState('');

  useEffect(() => {
    localStorage.setItem('lovia_draft', JSON.stringify(page));
  }, [page]);

  const handleProCheck = (feature: string) => {
    if (!isPro) {
      setModalFeature(feature);
      setIsUpgradeModalOpen(true);
      return false;
    }
    return true;
  };

  const handleDayChange = (dayName: ValentineDay) => {
    const dayData = VALENTINE_DAYS.find(d => d.name === dayName);
    setPage(prev => ({ ...prev, day: dayName, giftId: dayData?.giftId || prev.giftId }));
  };

  const handlePolish = async () => {
    if (!handleProCheck('AI Romantic Polish') || !page.message) return;
    setIsAILoading(true);
    try {
      const res = await getAIPolish(page.message);
      setPage(prev => ({ ...prev, message: res }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsAILoading(false);
    }
  };

  const handlePhotoUpload = (base64: string) => {
    setPage(prev => ({ ...prev, giftPhotoUrl: base64 } as any));
  };

  return (
    <div className="min-h-screen bg-[#FFFDF9] pt-32 pb-48 px-6">
      <UpgradeModal 
        isOpen={isUpgradeModalOpen} 
        onClose={() => setIsUpgradeModalOpen(false)} 
        onUpgrade={() => { setIsUpgradeModalOpen(false); onUpgrade(); }} 
        featureName={modalFeature}
      />

      <div className="max-w-4xl mx-auto space-y-12">
        <div className="flex items-center justify-between">
          <button onClick={onBack} className="p-4 hover:bg-pink-50 rounded-2xl transition-all active:scale-95">
            <ArrowLeft className="w-6 h-6 text-gray-400" />
          </button>
          <div className="flex items-center gap-4">
             <button onClick={() => onPublish(page)} className="px-10 py-3.5 bg-pink-500 text-white rounded-full font-bold shadow-romantic hover:bg-pink-600 hover:scale-105 active:scale-95 transition-all">
               Publish Story
             </button>
          </div>
        </div>

        {/* Main Box - Photo + Animation */}
        <div className="flex flex-col items-center gap-6 py-10">
          <label className="text-[10px] font-bold uppercase tracking-[0.4em] text-pink-300">The Visual Heart</label>
          <HiddenLoveGift 
            giftId={page.giftId || 'eternal-glow'} 
            photoUrl={(page as any).giftPhotoUrl} 
            isPro={isPro}
            onPhotoUpload={handlePhotoUpload}
          />
          <p className="text-xs text-gray-300 font-medium">Tap box to open, then tap again to upload photo</p>
        </div>

        <div className="glass-premium p-10 rounded-[3.5rem] border border-pink-50 space-y-10 shadow-xl">
          <div className="space-y-4">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Occasion</label>
            <div className="flex flex-wrap gap-2">
              {VALENTINE_DAYS.map(d => (
                <button key={d.name} onClick={() => handleDayChange(d.name)} className={`px-4 py-2 rounded-full text-[10px] font-bold transition-all ${page.day === d.name ? 'bg-pink-400 text-white' : 'bg-pink-50 text-pink-300'}`}>
                  {d.emoji} {d.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <input 
              value={page.title}
              onChange={e => setPage(prev => ({ ...prev, title: e.target.value }))}
              placeholder="Give your story a title..."
              className="w-full bg-transparent border-b border-pink-100 p-4 text-4xl font-bold font-quicksand focus:outline-none focus:border-pink-400 transition-colors"
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">The Message</label>
              <button onClick={handlePolish} disabled={isAILoading} className="flex items-center gap-2 text-pink-400 font-bold text-[10px] uppercase">
                {isAILoading ? <Clock className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />} AI Polish
              </button>
            </div>
            <textarea 
              value={page.message}
              onChange={e => setPage(prev => ({ ...prev, message: e.target.value }))}
              placeholder="Write your heart out..."
              className="w-full bg-pink-50/20 rounded-[2.5rem] p-8 font-romantic text-2xl border border-pink-50 focus:outline-none focus:bg-white transition-all min-h-[200px]"
            />
          </div>
        </div>

        {/* Timeline */}
        <div className="space-y-6">
          <div className="flex items-center justify-between">
            <h3 className="text-2xl font-bold text-gray-800 font-quicksand">Timeline of Us</h3>
            <button onClick={() => setPage(prev => ({ ...prev, timeline: [...prev.timeline, { id: Math.random().toString(36).substr(2, 9), date: 'Feb 2024', title: '', description: '' }] }))} className="p-2 bg-pink-50 text-pink-500 rounded-full"><Plus /></button>
          </div>
          <div className="grid gap-6">
            {page.timeline.map((t, i) => (
              <div key={t.id} className="bg-white p-6 rounded-[2.5rem] border border-pink-50 shadow-sm flex gap-6 items-center">
