import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Heart, Camera, Image as ImageIcon, Loader2 } from 'lucide-react';

interface PremiumGiftProps {
  giftId: string;
  className?: string;
  photoUrl?: string;
  isPro?: boolean;
  onPhotoUpload?: (base64: string) => void;
}

export const HiddenLoveGift: React.FC<PremiumGiftProps> = ({ giftId, className = "", photoUrl, isPro = false, onPhotoUpload }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence for the main photo specifically as requested
  const [internalPhoto, setInternalPhoto] = useState<string | null>(photoUrl || null);

  useEffect(() => {
    const saved = localStorage.getItem('lovia_main_photo');
    if (saved && !photoUrl) {
      setInternalPhoto(saved);
    } else if (photoUrl) {
      setInternalPhoto(photoUrl);
    }
  }, [photoUrl]);

  const handleBoxClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!isOpen) {
      setIsOpen(true);
    } else if (onPhotoUpload || !photoUrl) {
      fileInputRef.current?.click();
    }
  };

  const processImage = async (file: File) => {
    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const maxSize = 900;
          const sourceSize = Math.min(img.width, img.height);
          const targetSize = Math.min(sourceSize, maxSize);

          canvas.width = targetSize;
          canvas.height = targetSize;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.imageSmoothingEnabled = true;
            ctx.imageSmoothingQuality = 'high';
            const xOffset = (img.width - sourceSize) / 2;
            const yOffset = (img.height - sourceSize) / 2;
            ctx.drawImage(img, xOffset, yOffset, sourceSize, sourceSize, 0, 0, targetSize, targetSize);

            const base64 = canvas.toDataURL('image/jpeg', 0.85);
            setInternalPhoto(base64);
            localStorage.setItem('lovia_main_photo', base64);
            onPhotoUpload?.(base64);
          }
          setIsProcessing(false);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error("Photo processing failed", err);
      setIsProcessing(false);
    }
  };

  const activePhoto = photoUrl || internalPhoto;

  return (
    <div className={`flex flex-col items-center justify-center ${className}`}>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && processImage(e.target.files[0])} 
        accept="image/*" 
        className="hidden" 
      />
      <AnimatePresence mode="wait">
        {!isOpen ? (
          <motion.div
            key="closed"
            initial={{ scale: 0.9, opacity: 0 }}
            animate={{ 
              scale: [1, 1.05, 1], 
              opacity: 1, 
              y: [0, -8, 0],
              filter: ["drop-shadow(0 0 0px rgba(255,183,197,0))", "drop-shadow(0 0 20px rgba(255,183,197,0.4))", "drop-shadow(0 0 0px rgba(255,183,197,0))"]
            }}
            whileHover={{ scale: 1.1, rotate: 2 }}
            transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
            onClick={handleBoxClick}
            className="cursor-pointer relative w-64 h-64 flex items-center justify-center group"
          >
            <div className="absolute inset-0 bg-pink-200 blur-[60px] opacity-20 group-hover:opacity-40 transition-opacity" />
            <div className="relative w-full h-full bg-gradient-to-br from-pink-50 to-white rounded-[3.5rem] border-4 border-pink-100 shadow-romantic flex flex-col items-center justify-center gap-4 overflow-hidden">
               <motion.div animate={{ scale: [1, 1.2, 1] }} transition={{ duration: 1.5, repeat: Infinity }}>
                 <Heart className="w-16 h-16 text-pink-400 fill-pink-400" />
               </motion.div>
               <div className="text-center px-6">
                 <p className="text-[11px] font-bold uppercase tracking-[0.2em] text-pink-400">Unlock My Heart</p>
                 <Sparkles className="w-4 h-4 mx-auto mt-2 text-pink-300" />
               </div>
            </div>
          </motion.div>
        ) : (
          <motion.div
            key="opened"
            initial={{ scale: 0.8, opacity: 0, filter: 'blur(20px)' }}
            animate={{ scale: 1, opacity: 1, filter: 'blur(0px)' }}
            className="relative w-80 h-80 flex items-center justify-center cursor-pointer group"
            onClick={handleBoxClick}
          >
            <motion.div 
              animate={{ opacity: [0.1, 0.4, 0.1], scale: [1, 1.4, 1] }}
              transition={{ duration: 5, repeat: Infinity }}
              className="absolute inset-0 bg-pink-400 blur-[100px] pointer-events-none"
            />

            <div className="relative w-full h-full rounded-[3rem] border-8 border-white bg-white shadow-2xl overflow-hidden flex items-center justify-center">
              {activePhoto ? (
                <motion.img 
                  initial={{ scale: 1.2 }} 
                  animate={{ scale: 1 }} 
                  src={activePhoto} 
                  className="w-full h-full object-cover" 
                />
              ) : (
                <div className="flex flex-col items-center gap-3 text-pink-300">
                  {isProcessing ? <Loader2 className="w-10 h-10 animate-spin" /> : <Camera className="w-12 h-12" />}
                  <span className="text-[10px] font-bold uppercase tracking-widest text-center px-8">Add Your Main Memory</span>
                </div>
              )}

              <div className="absolute inset-0 pointer-events-none">
                <PremiumGiftVisuals giftId={giftId} />
              </div>

              <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                 <div className="bg-white/90 p-3 rounded-2xl shadow-lg">
                   <ImageIcon className="w-5 h-5 text-pink-500" />
                 </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

const PremiumGiftVisuals: React.FC<{ giftId: string }> = ({ giftId }) => {
  const animations: Record<string, React.ReactNode> = {
    'rose-petals': [...Array(10)].map((_, i) => (
      <motion.div key={i} className="absolute text-rose-400/30" initial={{ y: -20 }} animate={{ y: 400, x: Math.sin(i) * 100, rotate: 360 }} transition={{ duration: 4 + i, repeat: Infinity }} style={{ left: `${Math.random() * 100}%` }}>
        <Heart size={14} fill="currentColor" />
      </motion.div>
    )),
    'heart-bloom': <motion.div animate={{ scale: [1, 1.5, 1], opacity: [0.2, 0.5, 0.2] }} transition={{ duration: 2, repeat: Infinity }} className="w-full h-full bg-pink-400/20 blur-3xl" />,
    'eternal-glow': <motion.div animate={{ rotate: 360 }} transition={{ duration: 20, repeat: Infinity, ease: "linear" }} className="w-full h-full border-4 border-dashed border-white/50 rounded-full scale-90" />
  };
  return <>{animations[giftId] || animations['heart-bloom']}</>;
};

