import React, { useState, useEffect, useCallback } from 'react';
import { motion } from 'framer-motion';
import { 
  ArrowLeft, Sparkles, Plus, Wand2, Trash2, Camera, Loader2, Clock
} from 'lucide-react';
import { ValentineDay, LovePage } from '../types';
import { getAIPolish } from '../services/geminiService';
import { VALENTINE_DAYS, PREMIUM_GIFTS, TEMPLATES, EFFECTS } from '../constants';
import { HiddenLoveGift } from './PremiumGift';
import UpgradeModal from './UpgradeModal';

interface BuilderProps {
  initialDay: ValentineDay;
  onBack: () => void;
  onPublish: (page: LovePage) => void;
  isPro: boolean;
  onUpgrade: () => void;
}

const Builder: React.FC<BuilderProps> = ({ initialDay, onBack, onPublish, isPro, onUpgrade }) => {
  const [page, setPage] = useState<LovePage>(() => {
    const draft = localStorage.getItem('lovia_draft');
    if (draft) return JSON.parse(draft);
    return {
      id: Math.random().toString(36).substr(2, 9),
      day: initialDay,
      title: '',
      message: '',
      isSecret: false,
      templateId: 't1',
      giftId: VALENTINE_DAYS.find(d => d.name === initialDay)?.giftId || 'eternal-glow',
      effects: [],
      timeline: [],
      isPublished: false,
      publishedAt: 0,
      lastEdited: Date.now()
    };
  });

  const [isAILoading, setIsAILoading] = useState(false);
  const [isUpgradeModalOpen, setIsUpgradeModalOpen] = useState(false);
  const [modalFeature, setModalFeature] = useState('');

  useEffect(() => {
    localStorage.setItem('lovia_draft', JSON.stringify(page));
  }, [page]);

  const handleProCheck = (feature: string) => {
    if (!isPro) {
      setModalFeature(feature);
      setIsUpgradeModalOpen(true);
      return false;
    }
    return true;
  };

  const handleDayChange = (dayName: ValentineDay) => {
    const dayData = VALENTINE_DAYS.find(d => d.name === dayName);
    setPage(prev => ({ ...prev, day: dayName, giftId: dayData?.giftId || prev.giftId }));
  };

  const handlePolish = async () => {
    if (!handleProCheck('AI Romantic Polish') || !page.message) return;
    setIsAILoading(true);
    try {
      const res = await getAIPolish(page.message);
      setPage(prev => ({ ...prev, message: res }));
    } catch (e) {
      console.error("AI Polish Error", e);
    } finally {
      setIsAILoading(false);
    }
  };

  const handleMainPhotoUpload = (base64: string) => {
    setPage(prev => ({ ...prev, giftPhotoUrl: base64 } as any));
  };

  const handleTimelinePhoto = (id: string, base64: string) => {
    const updated = page.timeline.map(t => t.id === id ? { ...t, photoUrl: base64 } : t);
    setPage(prev => ({ ...prev, timeline: updated }));
    // Auto-sync if it's the first photo and main photo is empty
    if (!(page as any).giftPhotoUrl) {
      handleMainPhotoUpload(base64);
    }
  };

  const addMilestone = () => {
    if (!isPro && page.timeline.length >= 3) {
      handleProCheck('Unlimited Timeline Memories');
      return;
    }
    setPage(prev => ({ 
      ...prev, 
      timeline: [...prev.timeline, { 
        id: Math.random().toString(36).substr(2, 9), 
        date: 'Feb 14', 
        title: '', 
        description: '' 
      }] 
    }));
  };

  return (
    <div className="min-h-screen bg-[#FFFDF9] pt-32 pb-48 px-6">
      <UpgradeModal 
        isOpen={isUpgradeModalOpen} 
        onClose={() => setIsUpgradeModalOpen(false)} 
        onUpgrade={() => { setIsUpgradeModalOpen(false); onUpgrade(); }} 
        featureName={modalFeature}
      />

      <div className="max-w-4xl mx-auto space-y-12">
        <div className="flex items-center justify-between">
          <button onClick={onBack} className="p-4 hover:bg-pink-50 rounded-2xl transition-all active:scale-95">
            <ArrowLeft className="w-6 h-6 text-gray-400" />
          </button>
          <div className="flex items-center gap-4">
             <button onClick={() => onPublish(page)} className="px-10 py-3.5 bg-pink-500 text-white rounded-full font-bold shadow-romantic hover:bg-pink-600 hover:scale-105 active:scale-95 transition-all">
               Publish Story
             </button>
          </div>
        </div>

        {/* Main Photo Box - Unified Photo System */}
        <div className="flex flex-col items-center gap-6 py-6">
          <label className="text-[10px] font-bold uppercase tracking-[0.4em] text-pink-300">The Visual Heart</label>
          <HiddenLoveGift 
            giftId={page.giftId || 'eternal-glow'} 
            photoUrl={(page as any).giftPhotoUrl} 
            isPro={isPro}
            onPhotoUpload={handleMainPhotoUpload}
          />
          <p className="text-xs text-gray-300 font-medium">Click to open, then click photo to change</p>
        </div>

        <div className="glass-premium p-10 rounded-[3.5rem] border border-pink-50 space-y-10 shadow-xl">
          <div className="space-y-4">
            <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Choose the Occasion</label>
            <div className="flex flex-wrap gap-2">
              {VALENTINE_DAYS.map(d => (
                <button key={d.name} onClick={() => handleDayChange(d.name)} className={`px-4 py-2 rounded-full text-[10px] font-bold transition-all ${page.day === d.name ? 'bg-pink-400 text-white shadow-md' : 'bg-pink-50 text-pink-300 hover:bg-pink-100'}`}>
                  {d.emoji} {d.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <input 
              value={page.title}
              onChange={e => setPage(prev => ({ ...prev, title: e.target.value }))}
              placeholder="Give your story a title..."
              className="w-full bg-transparent border-b border-pink-100 p-4 text-4xl font-bold font-quicksand focus:outline-none focus:border-pink-400 transition-colors"
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <label className="text-[10px] font-bold uppercase tracking-widest text-pink-300">Your Emotional Note</label>
              <button onClick={handlePolish} disabled={isAILoading} className="flex items-center gap-2 text-pink-400 font-bold text-[10px] uppercase hover:text-pink-600 transition-colors">
                {isAILoading ? <Clock className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />} {isAILoading ? 'Polishing...' : 'AI Polish'}
              </button>
            </div>
            <textarea 
              value={page.message}
              onChange={e => setPage(prev => ({ ...prev, message: e.target.value }))}
              placeholder="Write what your heart feels..."
              className="w-full bg-pink-50/20 rounded-[2.5rem] p-8 font-romantic text-2xl border border-pink-50 focus:outline-none focus:bg-white transition-all min-h-[250px] resize-none"
            />
          </div>
        </div>

        {/* Timeline Refined */}
        <div className="space-y-8">
          <div className="flex items-center justify-between">
            <h3 className="text-2xl font-bold text-gray-800 font-quicksand">Timeline of Us</h3>
            <button onClick={addMilestone} className="flex items-center gap-2 px-5 py-2.5 bg-pink-50 text-pink-500 rounded-full font-bold text-xs hover:bg-pink-100 transition-all"><Plus size={16} /> Add Memory</button>
          </div>
          <div className="grid gap-6">
            {page.timeline.map((t, i) => (
              <div key={t.id} className="bg-white p-6 rounded-[2.5rem] border border-pink-50 shadow-sm flex flex-col md:flex-row gap-6 items-start md:items-center relative group">
                <div 
                  className="w-24 h-24 bg-pink-50 rounded-2xl flex items-center justify-center text-pink-200 cursor-pointer overflow-hidden relative shrink-0"
                  onClick={() => {
                    const input = document.createElement('input');
                    input.type = 'file';
                    input.accept = 'image/*';
                    input.onchange = (e: any) => {
                      const file = e.target.files[0];
                      if (file) {
                        const reader = new FileReader();
                        reader.onload = (re: any) => handleTimelinePhoto(t.id, re.target.result);
                        reader.readAsDataURL(file);
                      }
                    };
                    input.click();
                  }}
                >
                  {t.photoUrl ? <img src={t.photoUrl} className="w-full h-full object-cover rounded-2xl" /> : <Camera size={24} />}
                  <div className="absolute inset-0 bg-black/0 hover:bg-black/10 transition-colors" />
                </div>
                <div className="flex-1 space-y-2 w-full">
                  <input value={t.date} onChange={e => { const updated = [...page.timeline]; updated[i].date = e.target.value; setPage(p => ({ ...p, timeline: updated })); }} className="text-[10px] font-bold uppercase tracking-[0.2em] text-pink-300 bg-transparent focus:outline-none" />
                  <input value={t.title} onChange={e => { const updated = [...page.timeline]; updated[i].title = e.target.value; setPage(p => ({ ...p, timeline: updated })); }} placeholder="Chapter Title" className="w-full font-bold text-gray-700 bg-transparent focus:outline-none text-xl" />
                  <textarea value={t.description} onChange={e => { const updated = [...page.timeline]; updated[i].description = e.target.value; setPage(p => ({ ...p, timeline: updated })); }} placeholder="What happened then?" className="w-full text-sm text-gray-400 bg-transparent focus:outline-none resize-none" rows={1} />
                </div>
                <button onClick={() => setPage(prev => ({ ...prev, timeline: prev.timeline.filter(ev => ev.id !== t.id) }))} className="absolute top-6 right-6 text-gray-200 hover:text-red-400 md:relative md:top-auto md:right-auto transition-colors"><Trash2 size={18} /></button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Builder;

