                 initial={{ scale: 0, rotate: -20 }} 
                 animate={{ scale: 1.2, rotate: 0 }} 
                 className="text-7xl mb-10"
               >
                {currentDayInfo?.emoji}
               </motion.div>
               <h2 className="text-7xl md:text-[10rem] font-bold font-quicksand leading-none tracking-tighter drop-shadow-sm text-gray-800">{page.title}</h2>
               <div className="h-1 w-24 bg-pink-100 mx-auto mt-10 rounded-full" />
             </header>

             <article className="space-y-32 px-6 mb-80">
                {lines.slice(0, revealedLines).map((line, idx) => (
                  <motion.p 
                    key={idx} 
                    initial={{ opacity: 0, y: 50, filter: 'blur(10px)', textShadow: "0 0 20px rgba(255,183,197,0)" }} 
                    animate={{ 
                      opacity: 1, 
                      y: 0, 
                      filter: 'blur(0px)',
                      textShadow: ["0 0 20px rgba(255,183,197,0)", "0 0 20px rgba(255,183,197,0.3)", "0 0 20px rgba(255,183,197,0)"]
                    }} 
                    transition={{ duration: 1.5 }}
                    className="text-4xl md:text-8xl font-romantic leading-snug text-gray-800"
                  >
                    {line}
                  </motion.p>
                ))}
             </article>

             {isFinished && (
               <motion.div initial={{ opacity: 0, y: 100 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 1.5 }} className="space-y-80 pb-64">
                  <div className="flex flex-col items-center gap-12">
                     <motion.div animate={{ rotate: [0, 360] }} transition={{ duration: 10, repeat: Infinity, ease: "linear" }}>
                       <Sparkles className="w-10 h-10 text-pink-300" />
                     </motion.div>
                     <div className="text-[10px] font-bold uppercase tracking-[0.8em] text-pink-400">The Visual Essence</div>
                     <HiddenLoveGift 
                        giftId={page.giftId || 'eternal-glow'} 
                        photoUrl={(page as any).giftPhotoUrl} 
                        isPro={isPro}
                      />
                  </div>

                  {page.timeline.length > 0 && (
                    <div className="space-y-64">
                      <div className="space-y-4">
                        <h3 className="text-4xl md:text-6xl font-bold font-quicksand text-gray-300">Our Precious Chapters</h3>
                        <div className="w-20 h-1 bg-pink-50 mx-auto rounded-full" />
                      </div>
                      <div className="space-y-48">
                        {page.timeline.map((event, idx) => (
                          <motion.div 
                            key={event.id} 
                            initial={{ opacity: 0, x: idx % 2 === 0 ? -50 : 50 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            viewport={{ once: true, margin: "-100px" }}
                            className={`flex flex-col md:flex-row items-center gap-16 ${idx % 2 === 0 ? '' : 'md:flex-row-reverse'}`}
                          >
                            <div className="w-full md:w-1/2 rounded-[4rem] overflow-hidden shadow-2xl border-[12px] border-white aspect-square bg-pink-50 transform hover:scale-105 transition-transform duration-700">
