                  <footer className="flex flex-col items-center gap-16 py-32">
                     <motion.div animate={{ scale: [1, 1.3, 1] }} transition={{ duration: 2, repeat: Infinity }}>
                       <Heart className="w-20 h-20 text-pink-500 fill-current" />
                     </motion.div>
                     <p className="text-6xl md:text-9xl font-romantic text-gray-800">Always & Forever.</p>
                     <div className="text-[10px] font-bold uppercase tracking-[1em] opacity-20 mt-20">Lovia Digital Experience</div>
                  </footer>
