                  <p className="text-xs text-pink-400 font-bold uppercase tracking-[0.4em]">Cinematic Entry Key</p>
               </div>

               <div className="relative group p-6 bg-pink-50 rounded-[3rem] border-2 border-dashed border-pink-200 shadow-inner">
                  <img src={qrUrl} className="w-64 h-64 rounded-2xl" alt="Love QR" />
                  <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                    <Heart className="text-pink-400 fill-current w-12 h-12 animate-pulse" />
                  </div>
               </div>

               <div className="w-full space-y-4">
                  <motion.button 
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    onClick={handleNativeShare} 
                    className="w-full py-5 bg-pink-500 text-white rounded-[2rem] font-bold text-xl shadow-romantic flex items-center justify-center gap-3"
                  >
                    <Share2 className="w-5 h-5" /> 
                    {navigator.share ? 'Send to Partner' : 'Copy Link'}
                  </motion.button>

                  <button 
                    onClick={handleCopy}
                    className="w-full py-4 text-gray-400 font-bold uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 hover:text-pink-400 transition-colors"
                  >
                    {copied ? <Check size={14} className="text-green-500" /> : <Copy size={14} />}
                    {copied ? 'Link Captured' : 'Copy Secret URL'}
                  </button>
               </div>

               {isPro && (
                 <div className="flex items-center gap-2 px-6 py-2 bg-yellow-50 text-yellow-600 rounded-full text-[10px] font-bold uppercase tracking-widest border border-yellow-100">
                   <Download size={14} /> Download HQ QR for Printing
                 </div>
               )}

               {!isPro && (
                 <p className="text-[9px] text-gray-300 font-bold uppercase tracking-[0.3em]">Upgrade to PRO to customize QR skins</p>
               )}
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

