```tsx
import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Heart, Camera, Image as ImageIcon, Loader2, Gift as GiftIcon } from 'lucide-react';

interface PremiumGiftProps {
  giftId: string;
  className?: string;
  photoUrl?: string;
  isPro?: boolean;
  onPhotoUpload?: (base64: string) => void;
}

export const HiddenLoveGift: React.FC<PremiumGiftProps> = ({ giftId, className = "", photoUrl, isPro = false, onPhotoUpload }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Persistence for the main photo memory
  const [internalPhoto, setInternalPhoto] = useState<string | null>(photoUrl || null);

  useEffect(() => {
    const saved = localStorage.getItem('lovia_main_photo');
    if (saved && !photoUrl) {
      setInternalPhoto(saved);
    } else if (photoUrl) {
      setInternalPhoto(photoUrl);
    }
  }, [photoUrl]);

  const triggerUpload = (e: React.MouseEvent) => {
    e.stopPropagation();
    fileInputRef.current?.click();
  };

  const processImage = async (file: File) => {
    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const maxSize = 900;
          const sourceSize = Math.min(img.width, img.height);
          const targetSize = Math.min(sourceSize, maxSize);

          canvas.width = targetSize;
          canvas.height = targetSize;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.imageSmoothingEnabled = true;
            ctx.imageSmoothingQuality = 'high';
            const xOffset = (img.width - sourceSize) / 2;
            const yOffset = (img.height - sourceSize) / 2;
            ctx.drawImage(img, xOffset, yOffset, sourceSize, sourceSize, 0, 0, targetSize, targetSize);

            const base64 = canvas.toDataURL('image/jpeg', 0.85);
            setInternalPhoto(base64);
            localStorage.setItem('lovia_main_photo', base64);
            onPhotoUpload?.(base64);
          }
          setIsProcessing(false);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error("Photo processing failed", err);
      setIsProcessing(false);
    }
  };

  const activePhoto = photoUrl || internalPhoto;

  return (
    <div className={`flex flex-col items-center gap-12 ${className}`}>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && processImage(e.target.files[0])} 
        accept="image/*" 
        className="hidden" 
      />

      {/* [ Gift Frame ] - Always visible with photo inside */}
      <div className="relative group">
        <motion.div 
          animate={{ opacity: [0.1, 0.2, 0.1], scale: [1, 1.1, 1] }}
          transition={{ duration: 6, repeat: Infinity }}
          className="absolute inset-0 bg-pink-200 blur-[80px] -z-10"
        />
        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          onClick={triggerUpload}
          className="relative w-72 h-72 rounded-[2.5rem] border-[10px] border-white bg-white shadow-romantic overflow-hidden cursor-pointer flex items-center justify-center group"
        >
          {activePhoto ? (
            <motion.img 
              initial={{ scale: 1.1 }}
              animate={{ scale: 1 }}
              src={activePhoto} 
              className="w-full h-full object-cover" 
              alt="Memory" 
            />
          ) : (
            <div className="flex flex-col items-center gap-3 text-pink-300">
              {isProcessing ? <Loader2 className="w-8 h-8 animate-spin" /> : <Camera className="w-10 h-10" />}
              <span className="text-[10px] font-bold uppercase tracking-[0.2em]">Add Memory</span>
            </div>
          )}

          <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
            <div className="bg-white/90 p-3 rounded-2xl shadow-lg">
              <ImageIcon className="w-5 h-5 text-pink-500" />
            </div>
          </div>

          {/* Decorative Internal Border */}
          <div className="absolute inset-4 border-2 border-pink-50/30 rounded-3xl pointer-events-none" />
        </motion.div>
      </div>

      {/* [ Hidden Gift Box ] - Interactive section below */}
      <div className="flex flex-col items-center gap-4">
        <div className="text-[10px] font-bold uppercase tracking-[0.6em] text-pink-300">Secret Surprise</div>

        <AnimatePresence mode="wait">
          {!isOpen ? (
            <motion.div
              key="closed-box"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ 
                scale: [1, 1.05, 1], 
                opacity: 1, 
                y: [0, -5, 0]
              }}
              exit={{ scale: 1.2, opacity: 0, filter: 'blur(10px)' }}
              whileHover={{ scale: 1.1, rotate: 3 }}
              transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
              onClick={() => setIsOpen(true)}
              className="cursor-pointer relative w-48 h-48 flex items-center justify-center group"
            >
              <div className="absolute inset-0 bg-pink-400 blur-3xl opacity-10 group-hover:opacity-20 transition-opacity" />
              <div className="relative w-full h-full bg-gradient-to-br from-pink-50 to-lavender-50 rounded-[2.5rem] border-4 border-pink-100 shadow-romantic flex flex-col items-center justify-center gap-3 overflow-hidden">
                 <motion.div animate={{ scale: [1, 1.3, 1] }} transition={{ duration: 1.5, repeat: Infinity }}>
                   <Heart className="w-12 h-12 text-pink-400 fill-pink-400" />
                 </motion.div>
                 <Sparkles className="w-4 h-4 text-pink-300" />
              </div>
            </motion.div>
          ) : (
            <motion.div
              key="opened-gift"
              initial={{ scale: 0.8, opacity: 0, filter: 'blur(20px)' }}
              animate={{ scale: 1, opacity: 1, filter: 'blur(0px)' }}
              className="relative w-64 h-64 flex items-center justify-center"
            >
              <motion.div 
                animate={{ opacity: [0.1, 0.4, 0.1], scale: [1, 1.5, 1] }}
                transition={{ duration: 4, repeat: Infinity }}
                className="absolute inset-0 bg-pink-400 blur-[100px] pointer-events-none"
              />

              <div className="relative z-10 w-full h-full flex items-center justify-center">
                <PremiumGiftVisuals giftId={giftId} />
                <motion.div 
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.5 }}
                  className="absolute bottom-[-20px]"
                >
                  <GiftIcon className="w-8 h-8 text-pink-400 animate-bounce" />
                </motion.div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

const PremiumGiftVisuals: React.FC<{ giftId: string }> = ({ giftId }) => {
  const animations: Record<string, React.ReactNode> = {
    'rose-petals': [...Array(12)].map((_, i) => (
      <motion.div 
        key={i} 
        className="absolute text-rose-400/40" 
        initial={{ y: -50, opacity: 0 }} 
        animate={{ 
          y: 200, 
          x: Math.sin(i) * 120, 
          rotate: 360,
          opacity: [0, 1, 1, 0]
        }} 
        transition={{ duration: 5 + i * 0.2, repeat: Infinity }} 
        style={{ left: `${Math.random() * 100}%` }}
      >
        <Heart size={16} fill="currentColor" />
      </motion.div>
    )),
    'heart-bloom': (
      <motion.div 
        animate={{ 
          scale: [1, 1.4, 1], 
          opacity: [0.3, 0.6, 0.3],
          filter: ["blur(20px)", "blur(40px)", "blur(20px)"]
        }} 
        transition={{ duration: 3, repeat: Infinity }} 
        className="w-48 h-48 bg-pink-500/20 rounded-full"
      />
    ),
    'eternal-glow': (
      <div className="relative">
        <motion.div 
          animate={{ rotate: 360 }} 
          transition={{ duration: 15, repeat: Infinity, ease: "linear" }} 
          className="absolute inset-0 w-40 h-40 border-4 border-dashed border-pink-300 rounded-full scale-125 opacity-30" 
        />
        <Heart size={80} className="text-pink-500 fill-pink-500 drop-shadow-2xl animate-pulse" />
      </div>
    ),
    'soft-glow': (
      <motion.div 
        animate={{ scale: [1, 1.2, 1], opacity: [0.5, 0.8, 0.5] }}
        transition={{ duration: 3, repeat: Infinity }}
        className="text-7xl"
      >
        🍫
      </motion.div>
    )
  };
  return <>{animations[giftId] || animations['eternal-glow']}</>;
};

export default HiddenLoveGift;

