            localStorage.setItem('lovia_main_photo', base64);
            onPhotoUpload?.(base64);
          }
          setIsProcessing(false);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error("Photo processing failed", err);
      setIsProcessing(false);
    }
  };

  const activePhoto = photoUrl || internalPhoto;

  return (
    <div className={`flex flex-col items-center gap-12 ${className}`}>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && processImage(e.target.files[0])} 
        accept="image/*" 
        className="hidden" 
      />

      {/* [ Gift Frame ] - Always visible with photo inside */}
      <div className="relative group">
        <motion.div 
          animate={{ opacity: [0.1, 0.25, 0.1], scale: [1, 1.1, 1] }}
          transition={{ duration: 6, repeat: Infinity }}
          className="absolute inset-0 bg-pink-200 blur-[80px] -z-10"
        />
        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          onClick={triggerUpload}
          className="relative w-64 h-64 md:w-72 md:h-72 rounded-[3.5rem] border-[12px] border-white bg-white shadow-romantic overflow-hidden cursor-pointer flex items-center justify-center group ring-1 ring-pink-50"
        >
          {activePhoto ? (
            <motion.img 
              initial={{ scale: 1.1 }}
              animate={{ scale: 1 }}
              src={activePhoto} 
              className="w-full h-full object-cover" 
              alt="Memory" 
            />
          ) : (
            <div className="flex flex-col items-center gap-3 text-pink-300">
              {isProcessing ? <Loader2 className="w-8 h-8 animate-spin" /> : <Camera className="w-10 h-10" />}
              <span className="text-[10px] font-bold uppercase tracking-[0.2em]">Tap to add photo</span>
            </div>
          )}

          <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
            <div className="bg-white/90 p-3 rounded-2xl shadow-lg transform translate-y-2 group-hover:translate-y-0 transition-transform">
