      {/* [ Hidden Gift Box ] - Surprise section below frame */}
      <div className="flex flex-col items-center gap-4 w-full">
        <div className="text-[10px] font-bold uppercase tracking-[0.6em] text-pink-400/60 mb-2">Secret Surprise</div>

        <AnimatePresence mode="wait">
          {!isGiftOpen ? (
            <motion.div
              key="closed-box"
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ 
                scale: [1, 1.05, 1], 
                opacity: 1, 
                y: [0, -5, 0]
              }}
              exit={{ scale: 1.2, opacity: 0, filter: 'blur(15px)' }}
