              <div className="relative w-full h-full bg-gradient-to-br from-pink-50 via-white to-lavender-50 rounded-[2.5rem] border-4 border-pink-100 shadow-romantic flex flex-col items-center justify-center gap-3 overflow-hidden">
                 <motion.div animate={{ scale: [1, 1.3, 1] }} transition={{ duration: 1.5, repeat: Infinity }}>
