  };

  const handlePro = () => {
    if (!user) handleLogin();
    const proUser = { ...user!, isPro: true, proExpiry: Date.now() + 31536000000 };
    setUser(proUser);
    localStorage.setItem('lovia_user', JSON.stringify(proUser));
