    <motion.div 
      initial={{ opacity: 0, scale: 0.98 }} 
      animate={{ opacity: 1, scale: 1 }}
      transition={{ duration: 0.8 }}
      className={`min-h-screen relative flex flex-col items-center p-8 md:p-12 text-center bg-[#FFFDF9] overflow-x-hidden`}
    >
      {/* Background Cinematic Pulse */}
      <motion.div 
        animate={{ opacity: [0.02, 0.05, 0.02] }}
        transition={{ duration: 8, repeat: Infinity }}
        className="fixed inset-0 bg-pink-200 pointer-events-none z-0"
      />

      {/* Parallax Background Hearts */}
      <div className="fixed inset-0 pointer-events-none z-0 opacity-[0.08]">
        {[...Array(25)].map((_, i) => (
          <motion.div 
            key={i} 
