                      />
                  </div>

                  {page.timeline.length > 0 && (
                    <div className="space-y-64">
                      <div className="space-y-4">
                        <h3 className="text-4xl md:text-6xl font-bold font-quicksand text-gray-300">Our Precious Chapters</h3>
                        <div className="w-20 h-1 bg-pink-50 mx-auto rounded-full" />
                      </div>
                      <div className="space-y-48">
                        {page.timeline.map((event, idx) => (
                          <motion.div 
                            key={event.id} 
                            initial={{ opacity: 0, x: idx % 2 === 0 ? -50 : 50 }}
                            whileInView={{ opacity: 1, x: 0 }}
                            viewport={{ once: true, margin: "-100px" }}
                            className={`flex flex-col md:flex-row items-center gap-16 ${idx % 2 === 0 ? '' : 'md:flex-row-reverse'}`}
                          >
                            <div className="w-full md:w-1/2 rounded-[4rem] overflow-hidden shadow-2xl border-[12px] border-white aspect-square bg-pink-50 transform hover:scale-105 transition-transform duration-700">
                              {event.photoUrl ? (
                                <img src={event.photoUrl} className="w-full h-full object-cover" />
                              ) : (
                                <div className="w-full h-full flex items-center justify-center text-pink-200">
                                  <Heart size={80} />
                                </div>
                              )}
                            </div>
                            <div className="w-full md:w-1/2 text-left space-y-6 px-4">
                                <span className="text-xs font-bold text-pink-400 tracking-[0.4em] uppercase">{event.date}</span>
                                <h4 className="text-5xl md:text-7xl font-bold font-quicksand text-gray-800">{event.title}</h4>
                                <p className="text-3xl md:text-4xl font-romantic text-gray-400 italic leading-relaxed">"{event.description}"</p>
                            </div>
                          </motion.div>
                        ))}
                      </div>
                    </div>
                  )}

                  <footer className="flex flex-col items-center gap-16 py-32">
                     <motion.div animate={{ scale: [1, 1.3, 1] }} transition={{ duration: 2, repeat: Infinity }}>
                       <Heart className="w-20 h-20 text-pink-500 fill-current" />
                     </motion.div>
                     <p className="text-6xl md:text-9xl font-romantic text-gray-800">Always & Forever.</p>
                     <div className="text-[10px] font-bold uppercase tracking-[1em] opacity-20 mt-20">Lovia Digital Experience</div>
                  </footer>
               </motion.div>
             )}
          </motion.div>
        )}
      </AnimatePresence>

      <ShareModal 
        isOpen={isShareOpen} 
        onClose={() => setIsShareOpen(false)} 
        pageId={page.id} 
        isPro={isPro} 
      />
    </motion.div>
  );
};

export default Preview;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Copy, Check, Share2, Download, Heart } from 'lucide-react';

interface ShareModalProps {
  isOpen: boolean;
  onClose: () => void;
  pageId: string;
  isPro: boolean;
}

const ShareModal: React.FC<ShareModalProps> = ({ isOpen, onClose, pageId, isPro }) => {
  const [copied, setCopied] = useState(false);

  // Create a clean permanent URL using Search Params as requested
  const shareUrl = `${window.location.origin}/preview?id=${pageId}`;

  // Real working QR API integration
  const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=500x500&data=${encodeURIComponent(shareUrl)}&color=ec4899&format=png`;

  const handleCopy = () => {
    try {
      navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error("Copy failed", err);
    }
  };

  const handleNativeShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'My Lovia Love Story',
          text: 'Open this to see a special cinematic surprise I created for you. 💝',
          url: shareUrl,
        });
      } catch (e) {
        console.error("Native share cancelled or failed", e);
      }
    } else {
      handleCopy();
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <motion.div 
            className="absolute inset-0 bg-gray-900/80 backdrop-blur-3xl" 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }} 
            onClick={onClose} 
          />
          <motion.div 
            className="bg-white rounded-[4rem] p-12 max-w-lg w-full text-center relative shadow-2xl border border-pink-50" 
            initial={{ scale: 0.9, y: 40, opacity: 0 }} 
            animate={{ scale: 1, y: 0, opacity: 1 }} 
            exit={{ scale: 0.9, y: 40, opacity: 0 }}
          >
            <button onClick={onClose} className="absolute top-8 right-8 text-gray-300 hover:text-pink-500 transition-colors">
              <X className="w-8 h-8" />
            </button>
            <div className="space-y-12 flex flex-col items-center">
               <div className="text-left w-full space-y-2">
                  <h3 className="text-4xl font-bold text-gray-800 font-quicksand tracking-tight">The Love Passport</h3>
                  <p className="text-xs text-pink-400 font-bold uppercase tracking-[0.4em]">Cinematic Entry Key</p>
               </div>

               <div className="relative group p-6 bg-pink-50 rounded-[3rem] border-2 border-dashed border-pink-200 shadow-inner">
                  <img src={qrUrl} className="w-64 h-64 rounded-2xl" alt="Love QR" />
                  <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                    <Heart className="text-pink-400 fill-current w-12 h-12 animate-pulse" />
                  </div>
               </div>

               <div className="w-full space-y-4">
                  <motion.button 
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.98 }}
                    onClick={handleNativeShare} 
                    className="w-full py-5 bg-pink-500 text-white rounded-[2rem] font-bold text-xl shadow-romantic flex items-center justify-center gap-3"
                  >
                    <Share2 className="w-5 h-5" /> 
                    {navigator.share ? 'Send to Partner' : 'Copy Link'}
                  </motion.button>

                  <button 
                    onClick={handleCopy}
                    className="w-full py-4 text-gray-400 font-bold uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 hover:text-pink-400 transition-colors"
                  >
                    {copied ? <Check size={14} className="text-green-500" /> : <Copy size={14} />}
                    {copied ? 'Link Captured' : 'Copy Secret URL'}
                  </button>
               </div>

               {isPro && (
                 <div className="flex items-center gap-2 px-6 py-2 bg-yellow-50 text-yellow-600 rounded-full text-[10px] font-bold uppercase tracking-widest border border-yellow-100">
                   <Download size={14} /> Download HQ QR for Printing
                 </div>
               )}

               {!isPro && (
                 <p className="text-[9px] text-gray-300 font-bold uppercase tracking-[0.3em]">Upgrade to PRO to customize QR skins</p>
               )}
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export default ShareModal;

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Sparkles, Heart, Camera, Image as ImageIcon, Loader2, Gift as GiftIcon } from 'lucide-react';

interface PremiumGiftProps {
  giftId: string;
  className?: string;
  photoUrl?: string;
  isPro?: boolean;
  onPhotoUpload?: (base64: string) => void;
}

export const HiddenLoveGift: React.FC<PremiumGiftProps> = ({ giftId, className = "", photoUrl, isPro = false, onPhotoUpload }) => {
  const [isGiftOpen, setIsGiftOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [internalPhoto, setInternalPhoto] = useState<string | null>(photoUrl || null);

  useEffect(() => {
    const saved = localStorage.getItem('lovia_main_photo');
    if (saved && !photoUrl) {
      setInternalPhoto(saved);
    } else if (photoUrl) {
      setInternalPhoto(photoUrl);
    }
  }, [photoUrl]);

  const triggerUpload = (e: React.MouseEvent) => {
    e.stopPropagation();
    fileInputRef.current?.click();
  };

  const processImage = async (file: File) => {
    setIsProcessing(true);
    try {
      const reader = new FileReader();
      reader.onload = (event) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const maxSize = 900;
          const sourceSize = Math.min(img.width, img.height);
          const targetSize = Math.min(sourceSize, maxSize);

          canvas.width = targetSize;
          canvas.height = targetSize;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.imageSmoothingEnabled = true;
            ctx.imageSmoothingQuality = 'high';
            const xOffset = (img.width - sourceSize) / 2;
            const yOffset = (img.height - sourceSize) / 2;
            ctx.drawImage(img, xOffset, yOffset, sourceSize, sourceSize, 0, 0, targetSize, targetSize);

            const base64 = canvas.toDataURL('image/jpeg', 0.85);
            setInternalPhoto(base64);
            localStorage.setItem('lovia_main_photo', base64);
            onPhotoUpload?.(base64);
          }
          setIsProcessing(false);
        };
        img.src = event.target?.result as string;
      };
      reader.readAsDataURL(file);
    } catch (err) {
      console.error("Photo processing failed", err);
      setIsProcessing(false);
    }
  };

  const activePhoto = photoUrl || internalPhoto;

  return (
    <div className={`flex flex-col items-center gap-16 ${className}`}>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={(e) => e.target.files?.[0] && processImage(e.target.files[0])} 
        accept="image/*" 
        className="hidden" 
      />

      {/* [ Gift Frame ] - The Decorative Photo Holder */}
      <div className="relative">
        {/* Glow Aura */}
        <motion.div 
          animate={{ opacity: [0.1, 0.3, 0.1], scale: [1, 1.2, 1] }}
          transition={{ duration: 5, repeat: Infinity }}
          className="absolute inset-[-40px] bg-pink-200/50 blur-[60px] rounded-full -z-10"
        />

        <motion.div 
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          whileHover={{ scale: 1.02, rotate: -1 }}
          onClick={triggerUpload}
          className="relative w-72 h-72 md:w-80 md:h-80 bg-white p-4 rounded-[3rem] shadow-romantic border-2 border-pink-50 cursor-pointer overflow-visible group"
        >
           {/* The Frame Interior */}
           <div className="w-full h-full rounded-[2.2rem] bg-pink-50/30 overflow-hidden relative border-4 border-white/50 flex items-center justify-center">
              {activePhoto ? (
                <motion.img 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  src={activePhoto} 
                  className="w-full h-full object-cover" 
                  alt="Love Memory" 
                />
              ) : (
                <div className="flex flex-col items-center gap-3 text-pink-300">
                   {isProcessing ? <Loader2 className="w-8 h-8 animate-spin" /> : <Camera className="w-12 h-12" />}
                   <p className="text-[10px] font-bold uppercase tracking-widest">Tap to Frame Memory</p>
                </div>
              )}

              {/* Glass Overlay on Hover */}
              <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity backdrop-blur-[2px] flex items-center justify-center">
                 <div className="bg-white/90 p-3 rounded-2xl shadow-lg transform translate-y-2 group-hover:translate-y-0 transition-all">
                    <ImageIcon className="w-6 h-6 text-pink-500" />
                 </div>
              </div>
           </div>

           {/* Decorative Ribbon/Bow on the Frame */}
           <div className="absolute -top-6 left-1/2 -translate-x-1/2 z-20 pointer-events-none">
              <motion.div 
                animate={{ rotate: [-2, 2, -2] }}
                transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
                className="relative"
              >
                <div className="bg-pink-500 w-12 h-12 rounded-full shadow-lg flex items-center justify-center border-4 border-white">
                  <Heart className="w-6 h-6 text-white fill-current" />
                </div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 -z-10">
                   <div className="w-20 h-6 bg-pink-500 rounded-full blur-[1px] opacity-80" />
                   <div className="w-6 h-20 bg-pink-500 rounded-full blur-[1px] opacity-80 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2" />
                </div>
              </motion.div>
           </div>
        </motion.div>
      </div>

      {/* [ Hidden Gift Box ] - Interactive Reveal Below */}
      <div className="flex flex-col items-center gap-6 w-full relative z-10">
        <div className="text-[10px] font-bold uppercase tracking-[0.8em] text-pink-400 opacity-60">Unlock Secret Gift</div>

        <AnimatePresence mode="wait">
          {!isGiftOpen ? (
            <motion.div
              key="gift-closed"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ scale: 1.5, opacity: 0, filter: 'blur(20px)' }}
              whileHover={{ scale: 1.1 }}
              whileTap={{ scale: 0.9 }}
              onClick={() => setIsGiftOpen(true)}
              className="group cursor-pointer relative"
            >
               <motion.div 
                 animate={{ scale: [1, 1.1, 1], rotate: [0, 5, -5, 0] }}
                 transition={{ duration: 3, repeat: Infinity }}
                 className="w-48 h-48 bg-gradient-to-br from-pink-400 to-rose-400 rounded-[3rem] shadow-romantic flex flex-col items-center justify-center relative overflow-hidden"
               >
                  <GiftIcon className="w-16 h-16 text-white mb-2" />
                  <p className="text-[10px] font-bold text-white uppercase tracking-widest">Open Box</p>

                  {/* Subtle Shimmer */}
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
               </motion.div>
               <Sparkles className="absolute -top-4 -right-4 text-yellow-400 w-8 h-8 animate-pulse" />
            </motion.div>
          ) : (
            <motion.div
              key="gift-revealed"
              initial={{ opacity: 0, scale: 0.5, filter: 'blur(30px)' }}
              animate={{ opacity: 1, scale: 1, filter: 'blur(0px)' }}
              transition={{ type: "spring", damping: 15 }}
              className="relative w-72 h-72 flex items-center justify-center"
            >
               {/* Effect Background */}
               <motion.div 
                 animate={{ opacity: [0.1, 0.4, 0.1], scale: [1, 2, 1] }}
                 transition={{ duration: 4, repeat: Infinity }}
                 className="absolute inset-0 bg-pink-300 blur-[100px] -z-10"
               />

               <div className="relative z-10">
                  <PremiumGiftVisuals giftId={giftId} />
               </div>

               <motion.button 
                 initial={{ opacity: 0 }}
                 animate={{ opacity: 1 }}
                 transition={{ delay: 2 }}
                 onClick={() => setIsGiftOpen(false)}
                 className="absolute bottom-[-40px] text-[10px] font-bold text-pink-300 hover:text-pink-500 uppercase tracking-widest transition-colors"
               >
                 Close Box
               </motion.button>
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

const PremiumGiftVisuals: React.FC<{ giftId: string }> = ({ giftId }) => {
  const animations: Record<string, React.ReactNode> = {
    'rose-petals': [...Array(15)].map((_, i) => (
      <motion.div 
        key={i} 
        className="absolute text-rose-400/40" 
        initial={{ y: -100, opacity: 0, rotate: 0 }} 
        animate={{ 
          y: 300, 
          x: Math.sin(i) * 150, 
          rotate: 360,
          opacity: [0, 1, 1, 0]
        }} 
        transition={{ duration: 4 + i * 0.3, repeat: Infinity, delay: i * 0.1 }} 
        style={{ left: `${Math.random() * 100}%` }}
      >
        <Heart size={20} fill="currentColor" />
      </motion.div>
    )),
    'heart-bloom': (
      <div className="flex items-center justify-center">
         <motion.div 
           animate={{ 
             scale: [1, 2, 1], 
             opacity: [0.2, 0.5, 0.2],
             filter: ["blur(20px)", "blur(50px)", "blur(20px)"]
           }} 
           transition={{ duration: 3, repeat: Infinity }} 
           className="w-48 h-48 bg-pink-500 rounded-full"
         />
         <motion.div
           animate={{ scale: [1, 1.3, 1] }}
           transition={{ duration: 1.5, repeat: Infinity }}
           className="absolute"
         >
           <Heart size={80} className="text-pink-500 fill-pink-500 drop-shadow-2xl" />
         </motion.div>
      </div>
    ),
    'eternal-glow': (
      <div className="relative flex items-center justify-center">
        <motion.div 
          animate={{ rotate: 360 }} 
          transition={{ duration: 10, repeat: Infinity, ease: "linear" }} 
          className="absolute w-56 h-56 border-2 border-dashed border-pink-300 rounded-full opacity-40" 
        />
        <motion.div 
          animate={{ rotate: -360 }} 
          transition={{ duration: 15, repeat: Infinity, ease: "linear" }} 
          className="absolute w-44 h-44 border-2 border-dashed border-pink-400 rounded-full opacity-30" 
        />
        <Heart size={100} className="text-pink-500 fill-pink-500 drop-shadow-2xl" />
      </div>
    ),
    'soft-glow': (
      <motion.div 
        animate={{ scale: [1, 1.2, 1], rotate: [-10, 10, -10] }}
        transition={{ duration: 3, repeat: Infinity }}
        className="text-9xl drop-shadow-romantic"
      >
        🍫
      </motion.div>
    )
  };
  return <>{animations[giftId] || animations['eternal-glow']}</>;
};

export default HiddenLoveGift;

